  not exists(CatchBlock cb |
    te.getASuccessor+() = cb and
    cb.getASuccessor+() = d
  |
    canCatch(te, cb)
    or
    // Catch anything -- written as `catch(...)`.
    not exists(cb.getParameter())
  )
select te, "Exception thrown in destructor."

