Metrics/Files/ConditionalSegmentLines.ql:
/**
 * @name Number of conditionally compiled lines
 * @description The number of lines that are subject to conditional
 *              compilation constraints defined using `#if`, `#ifdef`,
 *              and `#ifndef`.
 * @kind treemap
 * @id cpp/conditional-segment-lines
 * @treemap.warnOn highValues
 * @metricType file
 * @metricAggregate avg sum max
 * @tags maintainability
 *       readability
 */

import cpp
import semmle.code.cpp.headers.MultipleInclusion

predicate preprocessorOpenCondition(PreprocessorDirective d, File f, int line) {
  (
    d instanceof PreprocessorIf or
    d instanceof PreprocessorIfdef or
    d instanceof PreprocessorIfndef
  ) and
  exists(Location l | l = d.getLocation() | f = l.getFile() and line = l.getStartLine())
}

predicate preprocessorCloseCondition(PreprocessorDirective d, File f, int line) {
  d instanceof PreprocessorEndif and
  exists(Location l | l = d.getLocation() | f = l.getFile() and line = l.getStartLine())
}

private predicate relevantLine(File f, int line) {
  preprocessorOpenCondition(_, f, line) or
  preprocessorCloseCondition(_, f, line)
}

predicate relevantDirective(PreprocessorDirective d, File f, int line) {
  preprocessorOpenCondition(d, f, line) or
  preprocessorCloseCondition(d, f, line)
}

private predicate relevantLineWithRank(File f, int rnk, int line) {
  line = rank[rnk](int l | relevantLine(f, l) | l)
}

private PreprocessorDirective next(PreprocessorDirective ppd) {
  exists(File f, int line, int rnk, int nextLine |
    relevantDirective(ppd, f, line) and
    relevantLineWithRank(f, rnk, line) and
    relevantLineWithRank(f, rnk + 1, nextLine) and
    relevantDirective(result, f, nextLine)
  )
}

private int level(PreprocessorDirective ppd) {
  relevantDirective(ppd, _, _) and
  not ppd = next(_) and
  result = 0
  or
  exists(PreprocessorDirective previous |
    ppd = next(previous) and
    preprocessorOpenCondition(previous, _, _) and
    result = level(previous) + 1
  )
  or
  exists(PreprocessorDirective previous |
    ppd = next(previous) and
    preprocessorCloseCondition(previous, _, _) and
    result = level(previous) - 1
  )
}

private predicate openWithDepth(int depth, File f, PreprocessorDirective open, int line) {
  preprocessorOpenCondition(open, f, line) and
  depth = level(open) and
  depth < 2 // beyond 2, we don't care about the macros anymore
}

private predicate closeWithDepth(int depth, File f, PreprocessorDirective close, int line) {
  preprocessorCloseCondition(close, f, line) and
  depth = level(close) - 1 and
  depth < 2 // beyond 2, we don't care about the macros anymore
}

predicate length(PreprocessorDirective open, int length) {
  exists(int depth, File f, int start, int end |
    openWithDepth(depth, f, open, start) and
    end =
      min(PreprocessorDirective endif, int closeLine |
        closeWithDepth(depth, f, endif, closeLine) and
        closeLine > start
      |
        closeLine
      ) and
    length = end - start - 1
  )
}

predicate headerGuard(PreprocessorDirective notdef, File f) {
  exists(CorrectIncludeGuard g | notdef = g.getIfndef() and f = notdef.getFile())
}

predicate headerGuardChild(PreprocessorDirective open) {
  exists(File f |
    headerGuard(_, f) and
    openWithDepth(1, f, open, _)
  )
}

predicate topLevelOpen(PreprocessorDirective open) {
  openWithDepth(0, _, open, _) and not headerGuard(open, _)
  or
  headerGuardChild(open)
}

from File f
where f.fromSource()
select f,
  sum(PreprocessorDirective open, int length |
    open.getFile() = f and
    topLevelOpen(open) and
    length(open, length)
  |
    length
  )

Security/CWE/CWE-311/CleartextBufferWrit:
/**
 * @name Cleartext storage of sensitive information in buffer
 * @description Storing sensitive information in cleartext can expose it
 *              to an attacker.
 * @kind path-problem
 * @problem.severity warning
 * @security-severity 7.5
 * @precision medium
 * @id cpp/cleartext-storage-buffer
 * @tags security
 *       external/cwe/cwe-312
 */

import cpp
import semmle.code.cpp.security.BufferWrite as BufferWrite
import semmle.code.cpp.security.SensitiveExprs
import semmle.code.cpp.security.FlowSources
import semmle.code.cpp.ir.dataflow.TaintTracking
import ToBufferFlow::PathGraph

/**
 * A buffer write into a sensitive expression.
 */
class SensitiveBufferWrite extends Expr instanceof BufferWrite::BufferWrite {
  SensitiveBufferWrite() { super.getDest() instanceof SensitiveExpr }

  /**
   * Gets a data source of this operation.
   */
  Expr getASource() { result = super.getASource() }

  /**
   * Gets the destination buffer of this operation.
   */
  Expr getDest() { result = super.getDest() }
}

/**
 * A taint flow configuration for flow from user input to a buffer write
 * into a sensitive expression.
 */
module ToBufferConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { source instanceof FlowSource }

  predicate isBarrier(DataFlow::Node node) {
    node.asExpr().getUnspecifiedType() instanceof IntegralType
  }

  predicate isSink(DataFlow::Node sink) { isSinkImpl(sink, _) }

  predicate observeDiffInformedIncrementalMode() { any() }

  Location getASelectedSinkLocation(DataFlow::Node sink) {
    exists(SensitiveBufferWrite w | result = [w.getLocation(), sink.getLocation()] |
      isSinkImpl(sink, w)
    )
  }
}

module ToBufferFlow = TaintTracking::Global<ToBufferConfig>;

predicate isSinkImpl(DataFlow::Node sink, SensitiveBufferWrite w) {
  w.getASource() = sink.asIndirectExpr()
}

from
  SensitiveBufferWrite w, ToBufferFlow::PathNode sourceNode, ToBufferFlow::PathNode sinkNode,
  FlowSource source
where
  ToBufferFlow::flowPath(sourceNode, sinkNode) and
  sourceNode.getNode() = source and
  isSinkImpl(sinkNode.getNode(), w)
select w, sourceNode, sinkNode,
  "This write into buffer '" + w.getDest().toString() + "' may contain unencrypted data from $@.",
  source, "user input (" + source.getSourceType() + ")"

Security/CWE/CWE-311/CleartextTransmissi:
/**
 * @name Cleartext transmission of sensitive information
 * @description Transmitting sensitive information across a network in
 *              cleartext can expose it to an attacker.
 * @kind path-problem
 * @problem.severity warning
 * @security-severity 7.5
 * @precision high
 * @id cpp/cleartext-transmission
 * @tags security
 *       external/cwe/cwe-319
 *       external/cwe/cwe-359
 */

import cpp
import semmle.code.cpp.security.SensitiveExprs
import semmle.code.cpp.security.PrivateData
import semmle.code.cpp.ir.dataflow.TaintTracking
import semmle.code.cpp.models.interfaces.FlowSource
import semmle.code.cpp.commons.File
import FromSensitiveFlow::PathGraph

class SourceVariable extends Variable {
  SourceVariable() {
    this instanceof SensitiveVariable or
    this instanceof PrivateDataVariable
  }
}

class SourceFunction extends Function {
  SourceFunction() {
    this instanceof SensitiveFunction or
    this instanceof PrivateDataFunction
  }
}

/**
 * A function that sends or receives data over a network.
 */
abstract class SendRecv extends Function {
  /**
   * Gets the expression for the socket or similar object used for sending or
   * receiving data through the function call `call` (if any).
   */
  abstract Expr getSocketExpr(Call call);

  /**
   * Gets the expression for the buffer to be sent from / received into through
   * the function call `call`.
   */
  abstract Expr getDataExpr(Call call);
}

/**
 * A function that sends data over a network.
 */
class Send extends SendRecv instanceof RemoteFlowSinkFunction {
  override Expr getSocketExpr(Call call) {
    call.getTarget() = this and
    exists(FunctionInput input, int arg |
      super.hasSocketInput(input) and
      (
        input.isParameter(arg) or
        input.isParameterDeref(arg)
      ) and
      result = call.getArgument(arg)
    )
  }

  override Expr getDataExpr(Call call) {
    call.getTarget() = this and
    exists(FunctionInput input, int arg |
      super.hasRemoteFlowSink(input, _) and
      input.isParameterDeref(arg) and
      result = call.getArgument(arg)
    )
  }
}

/**
 * A function that receives data over a network.
 */
class Recv extends SendRecv instanceof RemoteFlowSourceFunction {
  override Expr getSocketExpr(Call call) {
    call.getTarget() = this and
    exists(FunctionInput input, int arg |
      super.hasSocketInput(input) and
      (
        input.isParameter(arg) or
        input.isParameterDeref(arg)
      ) and
      result = call.getArgument(arg)
    )
  }

  override Expr getDataExpr(Call call) {
    call.getTarget() = this and
    exists(FunctionOutput output, int arg |
      super.hasRemoteFlowSource(output, _) and
      output.isParameterDeref(arg) and
      result = call.getArgument(arg)
    )
  }
}

/**
 * A function call that sends or receives data over a network.
 *
 * note: function calls such as `write` may be writing to a network source
 * or a file. We could attempt to determine which, and sort results into
 * `cpp/cleartext-transmission` and perhaps `cpp/cleartext-storage-file`. In
 * practice it usually isn't very important which query reports a result as
 * long as its reported exactly once.
 *
 * We do exclude function calls that specify an apparently constant socket,
 * which is likely to mean standard input, standard output or a similar channel.
 */
abstract class NetworkSendRecv extends FunctionCall {
  SendRecv target;

  NetworkSendRecv() {
    this.getTarget() = target and
    // exclude calls based on the socket...
    not exists(DataFlow::Node src, DataFlow::Node dest |
      DataFlow::localFlow(src, dest) and
      dest.asExpr() = target.getSocketExpr(this) and
      (
        // literal constant
        src.asExpr() instanceof Literal
        or
        // variable (such as a global) initialized to a literal constant
        exists(Variable v |
          v.getInitializer().getExpr() instanceof Literal and
          src.asExpr() = v.getAnAccess()
        )
        or
        // result of a function call with literal inputs (likely constant)
        forex(Expr arg | arg = src.asExpr().(FunctionCall).getAnArgument() | arg instanceof Literal)
        or
        // variable called `stdin`, `stdout` or `stderr`
        src.asExpr().(VariableAccess).getTarget().getName() = ["stdin", "stdout", "stderr"]
        or
        // open of `"/dev/tty"`
        exists(FunctionCall fc |
          fopenCall(fc) and
          fc.getAnArgument().getValue() = "/dev/tty" and
          src.asExpr() = fc
        )
        // (this is not exhaustive)
      )
    )
  }

  final Expr getDataExpr() { result = target.getDataExpr(this) }
}

/**
 * A function call that sends data over a network.
 */
class NetworkSend extends NetworkSendRecv {
  override Send target;
}

/**
 * A function call that receives data over a network.
 */
class NetworkRecv extends NetworkSendRecv {
  override Recv target;
}

pragma[noinline]
predicate encryptionFunction(Function f) {
  f.getName().toLowerCase().regexpMatch(".*(crypt|encode|decode|hash|securezero).*")
}

pragma[noinline]
predicate encryptionType(UserType t) {
  t.getName().toLowerCase().regexpMatch(".*(crypt|encode|decode|hash|securezero).*")
}

/**
 * An expression that is an argument or return value from an encryption /
 * decryption call. This is quite inclusive to minimize false positives, for
 * example `SecureZeroMemory` is not an encryption routine but a clue that
 * encryption may be present.
 */
class Encrypted extends Expr {
  Encrypted() {
    exists(FunctionCall fc |
      encryptionFunction(fc.getTarget()) and
      (
        this = fc or
        this = fc.getAnArgument()
      )
    )
    or
    exists(Type t |
      this.getType().refersTo(t) and
      encryptionType(t)
    )
  }
}

/**
 * Holds if `sink` is a node that represents data transmitted through a network
 * operation `nsr`.
 */
predicate isSinkSendRecv(DataFlow::Node sink, NetworkSendRecv nsr) {
  [sink.asIndirectExpr(), sink.asExpr()] = nsr.getDataExpr()
}

/**
 * Holds if `sink` is a node that is encrypted by `enc`.
 */
predicate isSinkEncrypt(DataFlow::Node sink, Encrypted enc) { sink.asExpr() = enc }

/**
 * Holds if `source` represents a use of a sensitive variable, or data returned by a
 * function returning sensitive data.
 */
predicate isSourceImpl(DataFlow::Node source) {
  exists(VariableAccess e |
    e = source.asExpr() and
    e.getTarget() instanceof SourceVariable
  )
  or
  source.asExpr().(FunctionCall).getTarget() instanceof SourceFunction
}

/**
 * A taint flow configuration for flow from a sensitive expression to a network
 * operation.
 */
module FromSensitiveConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { isSourceImpl(source) }

  predicate isSink(DataFlow::Node sink) { isSinkSendRecv(sink, _) }

  predicate isBarrier(DataFlow::Node node) {
    node.asExpr().getUnspecifiedType() instanceof IntegralType
  }

  predicate isBarrierIn(DataFlow::Node node) {
    // As any use of a sensitive variable is a potential source, we need to block flow into
    // sources to not get path duplication.
    isSource(node)
  }

  predicate observeDiffInformedIncrementalMode() { any() }

  Location getASelectedSinkLocation(DataFlow::Node sink) {
    exists(NetworkSendRecv networkSendRecv |
      result = [networkSendRecv.getLocation(), sink.getLocation()]
    |
      isSinkSendRecv(sink, networkSendRecv)
    )
  }
}

module FromSensitiveFlow = TaintTracking::Global<FromSensitiveConfig>;

/**
 * A taint flow configuration for flow from a sensitive expression to an encryption operation.
 */
module ToEncryptionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { FromSensitiveFlow::flow(source, _) }

  predicate isSink(DataFlow::Node sink) { isSinkEncrypt(sink, _) }

  predicate isBarrier(DataFlow::Node node) {
    node.asExpr().getUnspecifiedType() instanceof IntegralType
  }

  predicate isBarrierIn(DataFlow::Node node) {
    // As any use of a sensitive variable is a potential source, we need to block flow into
    // sources to not get path duplication.
    isSource(node)
  }

  predicate observeDiffInformedIncrementalMode() {
    none() // only used negatively
  }
}

module ToEncryptionFlow = TaintTracking::Global<ToEncryptionConfig>;

/**
 * A taint flow configuration for flow from an encryption operation to a network operation.
 */
module FromEncryptionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { isSinkEncrypt(source, _) }

  predicate isSink(DataFlow::Node sink) { FromSensitiveFlow::flowTo(sink) }

  predicate isBarrier(DataFlow::Node node) {
    node.asExpr().getUnspecifiedType() instanceof IntegralType
  }

  predicate observeDiffInformedIncrementalMode() {
    none() // only used negatively
  }
}

module FromEncryptionFlow = TaintTracking::Global<FromEncryptionConfig>;

from
  FromSensitiveFlow::PathNode source, FromSensitiveFlow::PathNode sink,
  NetworkSendRecv networkSendRecv, string msg
where
  // flow from sensitive -> network data
  FromSensitiveFlow::flowPath(source, sink) and
  isSinkSendRecv(sink.getNode(), networkSendRecv) and
  // no flow from sensitive -> evidence of encryption
  not ToEncryptionFlow::flow(source.getNode(), _) and
  not FromEncryptionFlow::flowTo(sink.getNode()) and
  // construct result
  if networkSendRecv instanceof NetworkSend
  then
    msg =
      "This operation transmits '" + sink.toString() +
        "', which may contain unencrypted sensitive data from $@."
  else
    msg =
      "This operation receives into '" + sink.toString() +
        "', which may put unencrypted sensitive data into $@."
select networkSendRecv, source, sink, msg, source.getNode(), source.getNode().toString()

/**
 * @name Cleartext storage of sensitive information in file
 * @description Storing sensitive information in cleartext can expose it
 *              to an attacker.
 * @kind path-problem
 * @problem.severity warning
 * @security-severity 7.5
 * @precision high
 * @id cpp/cleartext-storage-file
 * @tags security
 *       external/cwe/cwe-260
 *       external/cwe/cwe-313
 */

import cpp
import semmle.code.cpp.security.SensitiveExprs
import semmle.code.cpp.security.FileWrite
import semmle.code.cpp.ir.dataflow.DataFlow
import semmle.code.cpp.valuenumbering.GlobalValueNumbering
import semmle.code.cpp.ir.dataflow.TaintTracking
import FromSensitiveFlow::PathGraph

/**
 * A taint flow configuration for flow from a sensitive expression to a `FileWrite` sink.
 */
module FromSensitiveConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { isSourceImpl(source, _) }

  predicate isSink(DataFlow::Node sink) { isSinkImpl(sink, _, _) }

  predicate isBarrier(DataFlow::Node node) {
    node.asExpr().getUnspecifiedType() instanceof IntegralType
  }

  predicate observeDiffInformedIncrementalMode() { any() }

  Location getASelectedSourceLocation(DataFlow::Node sourceNode) {
    exists(SensitiveExpr source | result = [source.getLocation(), sourceNode.getLocation()] |
      isSourceImpl(sourceNode, source)
    )
  }

  Location getASelectedSinkLocation(DataFlow::Node sink) {
    exists(FileWrite w | result = [w.getLocation(), sink.getLocation()] | isSinkImpl(sink, w, _))
  }
}

module FromSensitiveFlow = TaintTracking::Global<FromSensitiveConfig>;

predicate isSinkImpl(DataFlow::Node sink, FileWrite w, Expr dest) {
  exists(Expr e |
    e = [sink.asExpr(), sink.asIndirectExpr()] and
    w.getASource() = e and
    dest = w.getDest() and
    // ignore things written with other conversion characters
    not exists(string convChar | convChar = w.getSourceConvChar(e) | not convChar = ["s", "S"]) and
    // exclude calls with standard streams
    not dest.(VariableAccess).getTarget().getName() = ["stdin", "stdout", "stderr"]
  )
}

predicate isSourceImpl(DataFlow::Node source, SensitiveExpr sensitive) {
  not isFileName(globalValueNumber(sensitive)) and // file names are not passwords
  source.asExpr() = sensitive
}

/**
 * An operation on a filename.
 */
predicate filenameOperation(FunctionCall op, Expr path) {
  exists(string name | name = op.getTarget().getName() |
    name =
      [
        "remove", "unlink", "rmdir", "rename", "fopen", "open", "freopen", "_open", "_wopen",
        "_wfopen", "_fsopen", "_wfsopen", "chmod", "chown", "stat", "lstat", "fstat", "access",
        "_access", "_waccess", "_access_s", "_waccess_s"
      ] and
    path = op.getArgument(0)
    or
    name = ["fopen_s", "wfopen_s", "rename"] and
    path = op.getArgument(1)
  )
}

predicate isFileName(GVN gvn) {
  exists(Expr path |
    filenameOperation(_, path) and
    gvn = globalValueNumber(path)
  )
}

from
  SensitiveExpr source, FromSensitiveFlow::PathNode sourceNode, FromSensitiveFlow::PathNode midNode,
  FileWrite w, Expr dest
where
  FromSensitiveFlow::flowPath(sourceNode, midNode) and
  isSourceImpl(sourceNode.getNode(), source) and
  isSinkImpl(midNode.getNode(), w, dest)
select w, sourceNode, midNode,
  "This write into file '" + dest.toString() + "' may contain unencrypted data from $@.", source,
  "this source."

Security/CWE/CWE-732/UnsafeDaclSecurityD:
/**
 * @name Setting a DACL to NULL in a SECURITY_DESCRIPTOR
 * @description Setting a DACL to NULL in a SECURITY_DESCRIPTOR will result in an unprotected object.
 *              If the DACL that belongs to the security descriptor of an object is set to NULL, a null DACL is created.
 *              A null DACL grants full access to any user who requests it;
 *              normal security checking is not performed with respect to the object.
 * @id cpp/unsafe-dacl-security-descriptor
 * @kind problem
 * @problem.severity error
 * @security-severity 7.8
 * @precision high
 * @tags security
 *       external/cwe/cwe-732
 */

import cpp
import semmle.code.cpp.ir.dataflow.DataFlow

/**
 * A function call to SetSecurityDescriptorDacl to set the ACL, specified by (2nd argument) bDaclPresent = TRUE
 */
class SetSecurityDescriptorDaclFunctionCall extends FunctionCall {
  SetSecurityDescriptorDaclFunctionCall() {
    this.getTarget().hasGlobalName("SetSecurityDescriptorDacl") and
    this.getArgument(1).getValue().toInt() != 0
  }
}

/**
 * Dataflow that detects a call to SetSecurityDescriptorDacl with a NULL DACL as the pDacl argument
 */
module NullDaclConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { source.asExpr() instanceof NullValue }

  predicate isSink(DataFlow::Node sink) {
    exists(SetSecurityDescriptorDaclFunctionCall call, VariableAccess val | val = sink.asExpr() |
      val = call.getArgument(2)
    )
  }

  predicate observeDiffInformedIncrementalMode() { any() }

  Location getASelectedSourceLocation(DataFlow::Node source) { none() }

  Location getASelectedSinkLocation(DataFlow::Node sink) {
    exists(SetSecurityDescriptorDaclFunctionCall call | result = call.getLocation() |
      sink.asExpr() = call.getArgument(2)
    )
  }
}

module NullDaclFlow = DataFlow::Global<NullDaclConfig>;

/**
 * Dataflow that detects a call to SetSecurityDescriptorDacl with a pDacl
 * argument that's _not_ likely to be NULL.
 */
module NonNullDaclConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source.getType().getUnspecifiedType().(PointerType).getBaseType() =
      any(Type t | t.getName() = "ACL").getUnspecifiedType() and
    (
      // If the value comes from a function whose body we can't see, assume
      // it's not null.
      exists(Call call |
        not exists(call.getTarget().getBlock()) and
        source.asExpr() = call
      )
      or
      // If the value is assigned by reference, assume it's not null. The data
      // flow library cannot currently follow flow from the body of a function to
      // an assignment by reference, so this rule applies whether we see the
      // body or not.
      exists(Call call | call.getAnArgument() = source.asDefiningArgument())
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(SetSecurityDescriptorDaclFunctionCall call | sink.asExpr() = call.getArgument(2))
  }

  predicate observeDiffInformedIncrementalMode() {
    none() // only used negatively
  }
}

module NonNullDaclFlow = DataFlow::Global<NonNullDaclConfig>;

from SetSecurityDescriptorDaclFunctionCall call, string message
where
  exists(NullValue nullExpr |
    message =
      "Setting a DACL to NULL in a SECURITY_DESCRIPTOR will result in an unprotected object."
  |
    call.getArgument(1).getValue().toInt() != 0 and
    call.getArgument(2) = nullExpr
  )
  or
  exists(VariableAccess var |
    message =
      "Setting a DACL to NULL in a SECURITY_DESCRIPTOR using variable " + var +
        " that is set to NULL will result in an unprotected object."
  |
    var = call.getArgument(2) and
    NullDaclFlow::flowToExpr(var) and
    not NonNullDaclFlow::flowToExpr(var)
  )
select call, message

Security/CWE/CWE-704/WcharCharConversion:
/**
 * @name Cast from char* to wchar_t*
 * @description Casting a byte string to a wide-character string is likely
 *              to yield a string that is incorrectly terminated or aligned.
 *              This can lead to undefined behavior, including buffer overruns.
 * @kind problem
 * @id cpp/incorrect-string-type-conversion
 * @problem.severity error
 * @security-severity 8.8
 * @precision high
 * @tags security
 *       external/cwe/cwe-704
 */

import cpp
import semmle.code.cpp.controlflow.Guards
import semmle.code.cpp.ir.IR

class WideCharPointerType extends PointerType {
  WideCharPointerType() { this.getBaseType() instanceof WideCharType }
}

/**
 * Given type `t`, recurses through and returns all
 * intermediate base types, including `t`.
 */
Type getABaseType(Type t) {
  result = t
  or
  result = getABaseType(t.(DerivedType).getBaseType())
  or
  result = getABaseType(t.(TypedefType).getBaseType())
}

/**
 * A type that may also be `CharPointerType`, but that are likely used as arbitrary buffers.
 */
class UnlikelyToBeAStringType extends Type {
  UnlikelyToBeAStringType() {
    exists(Type targ | getABaseType(this) = targ |
      // NOTE: not using CharType isUnsigned, but rather look for any explicitly declared unsigned
      // char types. Assuming these are used for buffers, not strings.
      targ.(CharType).getName().toLowerCase().matches("unsigned%") or
      targ.getName().toLowerCase().matches(["uint8_t", "%byte%"])
    )
  }
}

// Types that can be wide depending on the UNICODE macro
// see https://learn.microsoft.com/en-us/windows/win32/winprog/windows-data-types
class UnicodeMacroDependentWidthType extends Type {
  UnicodeMacroDependentWidthType() {
    exists(Type targ | getABaseType(this) = targ |
      targ.getName() in [
          "LPCTSTR",
          "LPTSTR",
          "PCTSTR",
          "PTSTR",
          "TBYTE",
          "TCHAR"
        ]
    )
  }
}

class UnicodeMacro extends Macro {
  UnicodeMacro() { this.getName().toLowerCase().matches("%unicode%") }
}

class UnicodeMacroInvocation extends MacroInvocation {
  UnicodeMacroInvocation() { this.getMacro() instanceof UnicodeMacro }
}

/**
 * Holds when a expression whose type is UnicodeMacroDependentWidthType and
 * is observed to be guarded by a check involving a bitwise-and operation
 * with a UnicodeMacroInvocation.
 * Such expressions are assumed to be checked dynamically, i.e.,
 * the flag would indicate if UNICODE typing is set correctly to allow
 * or disallow a widening cast.
 */
predicate isLikelyDynamicallyChecked(Expr e) {
  e.getType() instanceof UnicodeMacroDependentWidthType and
  exists(GuardCondition gc, BitwiseAndExpr bai, UnicodeMacroInvocation umi |
    bai.getAnOperand() = umi.getExpr()
  |
    // bai == 0 is false when reaching `e.getBasicBlock()`.
    // That is, bai != 0 when reaching `e.getBasicBlock()`.
    gc.ensuresEq(bai, 0, e.getBasicBlock(), false)
    or
    // bai == k and k != 0 is true when reaching `e.getBasicBlock()`.
    gc.ensuresEq(bai, any(int k | k != 0), e.getBasicBlock(), true)
  )
}

from Expr e1, Cast e2
where
  e2 = e1.getConversion() and
  exists(WideCharPointerType w, CharPointerType c |
    w = e2.getUnspecifiedType().(PointerType) and
    c = e1.getUnspecifiedType().(PointerType)
  ) and
  // Avoid `BYTE`-like casting as they are typically false positives
  // Example: `BYTE* buffer;` ... `(wchar_t*) buffer;`
  not e1.getType() instanceof UnlikelyToBeAStringType and
  // Avoid castings from 'new' expressions as typically these will be safe
  // Example: `__Type* ret = reinterpret_cast<__Type*>(New(m_pmo) char[num * sizeof(__Type)]);`
  not exists(NewOrNewArrayExpr newExpr | newExpr.getAChild*() = e1) and
  // Avoid cases where the cast is guarded by a check to determine if
  // unicode encoding is enabled in such a way to disallow the dangerous cast
  // at runtime.
  not isLikelyDynamicallyChecked(e1) and
  // Avoid cases in unreachable blocks.
  any(EnterFunctionInstruction e).getASuccessor+().getAst() = e1
select e1,
  "Conversion from " + e1.getType().toString() + " to " + e2.getType().toString() +
    ". Use of invalid string can lead to undefined behavior."

Security/CWE/CWE-295/SSLResultConflation:
/**
 * @name Certificate result conflation
 * @description Only accept SSL certificates that pass certificate verification.
 * @kind problem
 * @problem.severity error
 * @security-severity 7.5
 * @precision medium
 * @id cpp/certificate-result-conflation
 * @tags security
 *       external/cwe/cwe-295
 */

import cpp
import semmle.code.cpp.controlflow.Guards
import semmle.code.cpp.ir.dataflow.DataFlow

/**
 * A call to `SSL_get_verify_result`.
 */
class SslGetVerifyResultCall extends FunctionCall {
  SslGetVerifyResultCall() { this.getTarget().getName() = "SSL_get_verify_result" }
}

/**
 * Data flow from a call to `SSL_get_verify_result` to a guard condition
 * that references the result.
 */
module VerifyResultConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { source.asExpr() instanceof SslGetVerifyResultCall }

  predicate isSink(DataFlow::Node sink) {
    exists(GuardCondition guard | guard.(Expr).getAChild*() = sink.asExpr())
  }

  predicate observeDiffInformedIncrementalMode() { any() }

  Location getASelectedSinkLocation(DataFlow::Node sink) {
    exists(GuardCondition guard | result = guard.getLocation() |
      guard.comparesEq(sink.asExpr(), _, 0, false, _)
    )
  }
}

module VerifyResult = DataFlow::Global<VerifyResultConfig>;

from
  DataFlow::Node source, DataFlow::Node sink1, DataFlow::Node sink2, GuardCondition guard, Expr c1,
  Expr c2, boolean testIsTrue
where
  VerifyResult::flow(source, sink1) and
  VerifyResult::flow(source, sink2) and
  guard.comparesEq(sink1.asExpr(), c1, 0, false, testIsTrue) and // (value != c1) => testIsTrue
  guard.comparesEq(sink2.asExpr(), c2, 0, false, testIsTrue) and // (value != c2) => testIsTrue
  c1.getValue().toInt() = 0 and
  c2.getValue().toInt() != 0
select guard, "This expression conflates OK and non-OK results from $@.", source, source.toString()

Security/CWE/CWE-295/SSLResultNotChecked:
/**
 * @name Certificate not checked
 * @description Always check the result of certificate verification after fetching an SSL certificate.
 * @kind problem
 * @problem.severity error
 * @security-severity 7.5
 * @precision medium
 * @id cpp/certificate-not-checked
 * @tags security
 *       external/cwe/cwe-295
 */

import cpp
import semmle.code.cpp.valuenumbering.GlobalValueNumbering
import semmle.code.cpp.controlflow.IRGuards

/**
 * A call to `SSL_get_peer_certificate`.
 */
class SslGetPeerCertificateCall extends FunctionCall {
  SslGetPeerCertificateCall() {
    this.getTarget().getName() = "SSL_get_peer_certificate" // SSL_get_peer_certificate(ssl)
  }

  Expr getSslArgument() { result = this.getArgument(0) }
}

/**
 * A call to `SSL_get_verify_result`.
 */
class SslGetVerifyResultCall extends FunctionCall {
  SslGetVerifyResultCall() {
    this.getTarget().getName() = "SSL_get_verify_result" // SSL_get_peer_certificate(ssl)
  }

  Expr getSslArgument() { result = this.getArgument(0) }
}

/**
 * Holds if the SSL object passed into `SSL_get_peer_certificate` is checked with
 * `SSL_get_verify_result` entering `node`.
 */
predicate resultIsChecked(SslGetPeerCertificateCall getCertCall, ControlFlowNode node) {
  exists(Expr ssl, SslGetVerifyResultCall check |
    ssl = globalValueNumber(getCertCall.getSslArgument()).getAnExpr() and
    ssl = check.getSslArgument() and
    node = check
  )
}

/**
 * Holds if the certificate returned by `SSL_get_peer_certificate` is found to be
 * `0` on the edge `node1` to `node2`.
 */
predicate certIsZero(
  SslGetPeerCertificateCall getCertCall, ControlFlowNode node1, ControlFlowNode node2
) {
  exists(Expr cert |
    cert = globalValueNumber(getCertCall).getAnExpr() and
    node1.(GuardCondition).ensuresEqEdge(cert, 0, _, node2.getBasicBlock(), true)
  )
}

/**
 * Holds if the SSL object passed into `SSL_get_peer_certificate` has not been checked with
 * `SSL_get_verify_result` at `node`. Note that this is only computed at the call to
 * `SSL_get_peer_certificate` and at the start and end of `BasicBlock`s.
 */
predicate certNotChecked(SslGetPeerCertificateCall getCertCall, ControlFlowNode node) {
  // cert is not checked at the call to `SSL_get_peer_certificate`
  node = getCertCall
  or
  exists(BasicBlock bb, int pos |
    // flow to end of a `BasicBlock`
    certNotChecked(getCertCall, bb.getNode(pos)) and
    node = bb.getEnd() and
    // check for barrier node
    not exists(int pos2 |
      pos2 > pos and
      resultIsChecked(getCertCall, bb.getNode(pos2))
    )
  )
  or
  exists(BasicBlock pred, BasicBlock bb |
    // flow from the end of one `BasicBlock` to the beginning of a successor
    certNotChecked(getCertCall, pred.getEnd()) and
    bb = pred.getASuccessor() and
    node = bb.getStart() and
    // check for barrier bb
    not certIsZero(getCertCall, pred.getEnd(), bb.getStart())
  )
}

from SslGetPeerCertificateCall getCertCall, ControlFlowNode node
where
  certNotChecked(getCertCall, node) and
  node instanceof Function // (function exit)
select getCertCall,
  "This " + getCertCall.toString() + " is not followed by a call to SSL_get_verify_result."

Security/CWE/CWE-843/TypeConfusion.ql:
/**
 * @name Type confusion
 * @description Casting a value to an incompatible type can lead to undefined behavior.
 * @kind path-problem
 * @problem.severity warning
 * @security-severity 9.3
 * @precision medium
 * @id cpp/type-confusion
 * @tags security
 *       external/cwe/cwe-843
 */

import cpp
import semmle.code.cpp.dataflow.new.DataFlow
import Flow::PathGraph

/** Holds if `f` is the last field of its declaring class. */
predicate lastField(Field f) {
  exists(Class c | c = f.getDeclaringType() |
    f =
      max(Field cand, int byteOffset |
        cand.getDeclaringType() = c and byteOffset = f.getByteOffset()
      |
        cand order by byteOffset
      )
  )
}

/**
 * Holds if there exists a field in `c2` at offset `offset` that's compatible
 * with `f1`.
 */
bindingset[f1, offset, c2]
pragma[inline_late]
predicate hasCompatibleFieldAtOffset(Field f1, int offset, Class c2) {
  exists(Field f2 | offset = f2.getOffsetInClass(c2) |
    // Let's not deal with bit-fields for now.
    f2 instanceof BitField
    or
    f1.getUnspecifiedType().getSize() = f2.getUnspecifiedType().getSize()
    or
    lastField(f1) and
    f1.getUnspecifiedType().getSize() <= f2.getUnspecifiedType().getSize()
  )
}

/**
 * Holds if `c1` is a prefix of `c2`.
 */
bindingset[c1, c2]
pragma[inline_late]
predicate prefix(Class c1, Class c2) {
  not c1.isPolymorphic() and
  not c2.isPolymorphic() and
  if c1 instanceof Union
  then
    // If it's a union we just verify that one of it's variants is compatible with the other class
    exists(Field f1, int offset |
      // Let's not deal with bit-fields for now.
      not f1 instanceof BitField and
      offset = f1.getOffsetInClass(c1)
    |
      hasCompatibleFieldAtOffset(f1, offset, c2)
    )
  else
    forall(Field f1, int offset |
      // Let's not deal with bit-fields for now.
      not f1 instanceof BitField and
      offset = f1.getOffsetInClass(c1)
    |
      hasCompatibleFieldAtOffset(f1, offset, c2)
    )
}

/**
 * An unsafe cast is any explicit cast that is not
 * a `dynamic_cast`.
 */
class UnsafeCast extends Cast {
  private Class toType;

  UnsafeCast() {
    (
      this instanceof CStyleCast
      or
      this instanceof StaticCast
      or
      this instanceof ReinterpretCast
    ) and
    toType = this.getExplicitlyConverted().getUnspecifiedType().stripType() and
    not this.isImplicit() and
    exists(TypeDeclarationEntry tde |
      tde = toType.getDefinition() and
      not tde.isFromUninstantiatedTemplate(_)
    )
  }

  Class getConvertedType() { result = toType }

  /**
   * Holds if the result of this cast can safely be interpreted as a value of
   * type `t`.
   *
   * The compatibility rules are as follows:
   *
   * 1. the result of `(T)x` is compatible with the type `T` for any `T`
   * 2. the result of `(T)x` is compatible with the type `U` for any `U` such
   *    that `U` is a subtype of `T`, or `T` is a subtype of `U`.
   * 3. the result of `(T)x` is compatible with the type `U` if the list
   *    of fields of `T` is a prefix of the list of fields of `U`.
   *    For example, if `U` is `struct { unsigned char x; int y; };`
   *    and `T` is `struct { unsigned char uc; };`.
   * 4. the result of `(T)x` is compatible with the type `U` if the list
   *    of fields of `U` is a prefix of the list of fields of `T`.
   *
   *    Condition 4 is a bit controversial, since it assumes that the additional
   *    fields in `T` won't be accessed. This may result in some FNs.
   */
  bindingset[this, t]
  pragma[inline_late]
  predicate compatibleWith(Type t) {
    // Conition 1
    t.stripType() = this.getConvertedType()
    or
    // Condition 3
    prefix(this.getConvertedType(), t.stripType())
    or
    // Condition 4
    prefix(t.stripType(), this.getConvertedType())
    or
    // Condition 2 (a)
    t.stripType().(Class).getABaseClass+() = this.getConvertedType()
    or
    // Condition 2 (b)
    t.stripType() = this.getConvertedType().getABaseClass+()
  }
}

/**
 * Holds if `source` is an allocation that allocates a value of type `type`.
 */
predicate isSourceImpl(DataFlow::Node source, Class type) {
  exists(AllocationExpr alloc |
    alloc = source.asExpr() and
    type = alloc.getAllocatedElementType().stripType() and
    not exists(
      alloc
          .(NewOrNewArrayExpr)
          .getAllocator()
          .(OperatorNewAllocationFunction)
          .getPlacementArgument()
    )
  ) and
  exists(TypeDeclarationEntry tde |
    tde = type.getDefinition() and
    not tde.isFromUninstantiatedTemplate(_)
  )
}

/** A configuration describing flow from an allocation to a potentially unsafe cast. */
module Config implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { isSourceImpl(source, _) }

  predicate isBarrier(DataFlow::Node node) {
    // We disable flow through global variables to reduce FPs from infeasible paths
    node instanceof DataFlow::VariableNode
    or
    exists(Class c | c = node.getType().stripType() |
      not c.hasDefinition()
      or
      exists(TypeDeclarationEntry tde |
        tde = c.getDefinition() and
        tde.isFromUninstantiatedTemplate(_)
      )
    )
  }

  predicate isSink(DataFlow::Node sink) { sink.asExpr() = any(UnsafeCast cast).getUnconverted() }

  int fieldFlowBranchLimit() { result = 0 }

  predicate observeDiffInformedIncrementalMode() {
    none() // used both positively and negatively
  }
}

module Flow = DataFlow::Global<Config>;

predicate relevantType(DataFlow::Node sink, Class allocatedType) {
  exists(DataFlow::Node source |
    Flow::flow(source, sink) and
    isSourceImpl(source, allocatedType)
  )
}

predicate isSinkImpl(
  DataFlow::Node sink, Class allocatedType, Type convertedType, boolean compatible
) {
  exists(UnsafeCast cast |
    relevantType(sink, allocatedType) and
    sink.asExpr() = cast.getUnconverted() and
    convertedType = cast.getConvertedType()
  |
    if cast.compatibleWith(allocatedType) then compatible = true else compatible = false
  )
}

from
  Flow::PathNode source, Flow::PathNode sink, Type badSourceType, Type sinkType,
  DataFlow::Node sinkNode
where
  Flow::flowPath(source, sink) and
  sinkNode = sink.getNode() and
  isSourceImpl(source.getNode(), badSourceType) and
  isSinkImpl(sinkNode, badSourceType, sinkType, false) and
  // If there is any flow that would result in a valid cast then we don't
  // report an alert here. This reduces the number of FPs from infeasible paths
  // significantly.
  not exists(DataFlow::Node goodSource, Type goodSourceType |
    isSourceImpl(goodSource, goodSourceType) and
    isSinkImpl(sinkNode, goodSourceType, sinkType, true) and
    Flow::flow(goodSource, sinkNode)
  )
select sinkNode, source, sink, "Conversion from $@ to $@ is invalid.", badSourceType,
  badSourceType.toString(), sinkType, sinkType.toString()

Security/CWE/CWE-022/TaintedPath.ql:
/**
 * @name Uncontrolled data used in path expression
 * @description Accessing paths influenced by users can allow an
 *              attacker to access unexpected resources.
 * @kind path-problem
 * @problem.severity warning
 * @security-severity 7.5
 * @precision medium
 * @id cpp/path-injection
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-023
 *       external/cwe/cwe-036
 *       external/cwe/cwe-073
 */

import cpp
import semmle.code.cpp.security.FunctionWithWrappers
import semmle.code.cpp.security.FlowSources
import semmle.code.cpp.ir.IR
import semmle.code.cpp.ir.dataflow.TaintTracking
import TaintedPath::PathGraph

/**
 * A function for opening a file.
 */
class FileFunction extends FunctionWithWrappers {
  FileFunction() {
    exists(string nme | this.hasGlobalName(nme) |
      nme = ["fopen", "_fopen", "_wfopen", "open", "_open", "_wopen"]
      or
      // create file function on windows
      nme.matches("CreateFile%")
    )
    or
    this.hasQualifiedName("std", "fopen")
    or
    // on any of the fstream classes, or filebuf
    exists(string nme | this.getDeclaringType().hasQualifiedName("std", nme) |
      nme = ["basic_fstream", "basic_ifstream", "basic_ofstream", "basic_filebuf"]
    ) and
    // we look for either the open method or the constructor
    (this.getName() = "open" or this instanceof Constructor)
  }

  // conveniently, all of these functions take the path as the first parameter!
  override predicate interestingArg(int arg) { arg = 0 }
}

/**
 * Holds for a variable that has any kind of upper-bound check anywhere in the program.
 * This is biased towards being inclusive and being a coarse overapproximation because
 * there are a lot of valid ways of doing an upper bounds checks if we don't consider
 * where it occurs, for example:
 * ```cpp
 *   if (x < 10) { sink(x); }
 *
 *   if (10 > y) { sink(y); }
 *
 *   if (z > 10) { z = 10; }
 *   sink(z);
 * ```
 */
predicate hasUpperBoundsCheck(Variable var) {
  exists(RelationalOperation oper, VariableAccess access |
    oper.getAnOperand() = access and
    access.getTarget() = var and
    // Comparing to 0 is not an upper bound check
    not oper.getAnOperand().getValue() = "0"
  )
}

module TaintedPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node node) { node instanceof FlowSource }

  predicate isSink(DataFlow::Node node) {
    exists(FileFunction fileFunction |
      fileFunction.outermostWrapperFunctionCall(node.asIndirectArgument(), _)
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    node.asExpr().(Call).getTarget().getUnspecifiedType() instanceof ArithmeticType
    or
    exists(LoadInstruction load, Variable checkedVar |
      load = node.asInstruction() and
      checkedVar = load.getSourceAddress().(VariableAddressInstruction).getAstVariable() and
      hasUpperBoundsCheck(checkedVar)
    )
  }

  predicate isBarrierOut(DataFlow::Node node) {
    // make sinks barriers so that we only report the closest instance
    isSink(node)
  }

  predicate observeDiffInformedIncrementalMode() { any() }

  Location getASelectedSinkLocation(DataFlow::Node sink) {
    result = sink.asIndirectArgument().getLocation()
  }
}

module TaintedPath = TaintTracking::Global<TaintedPathConfig>;

from
  FileFunction fileFunction, Expr taintedArg, FlowSource taintSource,
  TaintedPath::PathNode sourceNode, TaintedPath::PathNode sinkNode, string callChain
where
  taintedArg = sinkNode.getNode().asIndirectArgument() and
  fileFunction.outermostWrapperFunctionCall(taintedArg, callChain) and
  TaintedPath::flowPath(sourceNode, sinkNode) and
  taintSource = sourceNode.getNode()
select taintedArg, sourceNode, sinkNode,
  "This argument to a file access function is derived from $@ and then passed to " + callChain + ".",
  taintSource, "user input (" + taintSource.getSourceType() + ")"

Security/CWE/CWE-170/ImproperNullTermina:
/**
 * @name User-controlled data may not be null terminated
 * @description String operations on user-controlled strings can result in
 *              buffer overflow or buffer over-read.
 * @kind problem
 * @id cpp/user-controlled-null-termination-tainted
 * @problem.severity warning
 * @security-severity 10.0
 * @tags security
 *       external/cwe/cwe-170
 */

import cpp
import semmle.code.cpp.commons.NullTermination
import semmle.code.cpp.security.FlowSources as FS
import semmle.code.cpp.dataflow.new.TaintTracking
import semmle.code.cpp.ir.IR

predicate isSource(FS::FlowSource source, string sourceType) {
  sourceType = source.getSourceType() and
  exists(VariableAccess va, Call call |
    va = source.asDefiningArgument() and
    call.getAnArgument() = va and
    va.getTarget() instanceof SemanticStackVariable and
    call.getTarget().hasGlobalName(["read", "fread", "recv", "recvfrom", "recvmsg"])
  )
}

predicate isSink(DataFlow::Node sink, VariableAccess va) {
  va = [sink.asExpr(), sink.asIndirectExpr()] and
  variableMustBeNullTerminated(va)
}

private module Config implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { isSource(source, _) }

  predicate isBarrier(DataFlow::Node node) {
    isSink(node) and node.asExpr().getUnspecifiedType() instanceof ArithmeticType
    or
    node.asCertainDefinition().getUnspecifiedType() instanceof ArithmeticType
    or
    mayAddNullTerminator(_, node.asIndirectExpr())
  }

  predicate isSink(DataFlow::Node sink) { isSink(sink, _) }

  predicate observeDiffInformedIncrementalMode() { any() }

  Location getASelectedSinkLocation(DataFlow::Node sink) {
    exists(VariableAccess va | result = va.getLocation() | isSink(sink, va))
  }
}

module Flow = TaintTracking::Global<Config>;

from DataFlow::Node source, DataFlow::Node sink, VariableAccess va, string sourceType
where
  Flow::flow(source, sink) and
  isSource(source, sourceType) and
  isSink(sink, va)
select va, "String operation depends on $@ that may not be null terminated.", source, sourceType

Security/CWE/CWE-290/AuthenticationBypas:
/**
 * @name Authentication bypass by spoofing
 * @description Authentication by checking that the peer's address
 *              matches a known IP or web address is unsafe as it is
 *              vulnerable to spoofing attacks.
 * @kind path-problem
 * @problem.severity warning
 * @security-severity 8.1
 * @precision medium
 * @id cpp/user-controlled-bypass
 * @tags security
 *       external/cwe/cwe-290
 */

import cpp
import semmle.code.cpp.dataflow.new.TaintTracking
import semmle.code.cpp.security.FlowSources as FS
import Flow::PathGraph

string getATopLevelDomain() {
  result =
    [
      "com", "ru", "net", "org", "de", "jp", "uk", "br", "pl", "in", "it", "fr", "au", "info", "nl",
      "cn", "ir", "es", "cz", "biz", "ca", "eu", "ua", "kr", "za", "co", "gr", "ro", "se", "tw",
      "vn", "mx", "ch", "tr", "at", "be", "hu", "tv", "dk", "me", "ar", "us", "no", "sk", "fi",
      "id", "cl", "nz", "by", "xyz", "pt", "ie", "il", "kz", "my", "hk", "lt", "cc", "sg", "io",
      "edu", "gov"
    ]
}

predicate hardCodedAddressOrIP(StringLiteral txt) {
  exists(string s | s = txt.getValueText() |
    // Hard-coded ip addresses, such as 127.0.0.1
    s.regexpMatch("\"[0-9]+[.][0-9]+[.][0-9]+[.][0-9]+\"") or
    // Hard-coded addresses such as www.mycompany.com
    s.regexpMatch("\"(www\\.|http:|https:).*\"") or
    s.regexpMatch("\".*\\.(" + strictconcat(getATopLevelDomain(), "|") + ")\"")
  )
}

predicate useOfHardCodedAddressOrIP(Expr use) {
  hardCodedAddressOrIP(use)
  or
  exists(Expr def, Expr src, Variable v |
    useOfHardCodedAddressOrIP(src) and
    exprDefinition(v, def, src) and
    definitionUsePair(v, def, use)
  )
}

/**
 * Find `IfStmt`s that have a hard-coded IP or web address in
 * their condition. If the condition also depends on an
 * untrusted input then it might be vulnerable to a spoofing
 * attack.
 */
predicate hardCodedAddressInCondition(Expr subexpression, Expr condition) {
  subexpression = condition.getAChild+() and
  // One of the sub-expressions of the condition is a hard-coded
  // IP or web-address.
  exists(Expr use | use = condition.getAChild+() | useOfHardCodedAddressOrIP(use)) and
  condition = any(IfStmt ifStmt).getCondition()
}

predicate isSource(FS::FlowSource source, string sourceType) { source.getSourceType() = sourceType }

predicate isSink(DataFlow::Node sink, Expr condition) {
  hardCodedAddressInCondition([sink.asExpr(), sink.asIndirectExpr()], condition)
}

module Config implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) { isSource(source, _) }

  predicate isSink(DataFlow::Node sink) { isSink(sink, _) }

  predicate observeDiffInformedIncrementalMode() { any() }

  Location getASelectedSinkLocation(DataFlow::Node sink) {
    exists(Expr condition | result = [condition.getLocation(), sink.getLocation()] |
      isSink(sink, condition)
    )
  }
