jsf/4.10 Classes/AV Rule 79.ql:
/**
 * @name Resource not released in destructor
 * @description All resources acquired by a class should be released by its destructor. Avoid the use of the 'open / close' pattern, since C++ constructors and destructors provide a safer way to handle resource acquisition and release. Best practice in C++ is to use the 'RAII' technique: constructors allocate resources and destructors free them.
 * @kind problem
 * @problem.severity warning
 * @precision high
 * @id cpp/resource-not-released-in-destructor
 * @tags efficiency
 *       readability
 *       external/cwe/cwe-404
 *       external/jsf
 */

import cpp
import Critical.NewDelete
import semmle.code.cpp.valuenumbering.GlobalValueNumbering

/**
 * An expression that acquires a resource, and the kind of resource that is acquired.  The
 * kind of a resource indicates which acquisition/release expressions can be paired.
 */
predicate acquireExpr(Expr acquire, string kind) {
  exists(FunctionCall fc, Function f, string name |
    fc = acquire and
    f = fc.getTarget() and
    f.hasGlobalOrStdName(name) and
    (
      name = "fopen" and
      kind = "file"
      or
      name = "open" and
      kind = "file descriptor"
      or
      name = "socket" and
      kind = "file descriptor"
    )
  )
  or
  allocExpr(acquire, kind)
}

/**
 * An expression that releases a resource, and the kind of resource that is released.  The
 * kind of a resource indicates which acquisition/release expressions can be paired.
 */
predicate releaseExpr(Expr release, Expr resource, string kind) {
  exists(FunctionCall fc, Function f, string name |
    fc = release and
    f = fc.getTarget() and
    f.hasGlobalOrStdName(name) and
    (
      name = "fclose" and
      resource = fc.getArgument(0) and
      kind = "file"
      or
      name = "close" and
      resource = fc.getArgument(0) and
      kind = "file descriptor"
    )
  )
  or
  exists(string releaseKind |
    freeExpr(release, resource, releaseKind) and
    (
      kind = "malloc" and
      releaseKind = "free"
      or
      kind = "new" and
      releaseKind = "delete"
      or
      kind = "new[]" and
      releaseKind = "delete[]"
    )
  )
}

/**
 * Gets the expression `e` or a `PointerDereferenceExpr` around
 * it.
 */
Expr exprOrDereference(Expr e) {
  result = e or
  result.(PointerDereferenceExpr).getOperand() = e
}

/**
 * Holds if the expression `e` releases expression `released`, whether directly
 * or via one or more function call(s).
 */
private predicate exprReleases(Expr e, Expr released, string kind) {
  // `e` is a call to a release function and `released` is the released argument
  releaseExpr(e, released, kind)
  or
  exists(int arg, VariableAccess access, Function f |
    // `e` is a call to a function that releases one of it's parameters,
    // and `released` is the corresponding argument
    (
      e.(FunctionCall).getTarget() = f or
      e.(FunctionCall).getTarget().(MemberFunction).getAnOverridingFunction+() = f
    ) and
    access = f.getParameter(pragma[only_bind_into](arg)).getAnAccess() and
    e.(FunctionCall).getArgument(pragma[only_bind_into](arg)) = released and
    exprReleases(_,
      pragma[only_bind_into](exprOrDereference(globalValueNumber(access).getAnExpr())), kind)
  )
  or
  exists(Function f, ThisExpr innerThis |
    // `e` is a call to a method that releases `this`, and `released`
    // is the object that is called
    (
      e.(FunctionCall).getTarget() = f or
      e.(FunctionCall).getTarget().(MemberFunction).getAnOverridingFunction+() = f
    ) and
    e.(FunctionCall).getQualifier() = exprOrDereference(released) and
    innerThis.getEnclosingFunction() = f and
    exprReleases(_, pragma[only_bind_into](globalValueNumber(innerThis).getAnExpr()), kind)
  )
}

class Resource extends MemberVariable {
  Resource() { not this.isStatic() }

  // Check that an expr is somewhere in this class - does not have to be a constructor
  predicate inSameClass(Expr e) {
    e.getEnclosingFunction().(MemberFunction).getDeclaringType() = this.getDeclaringType()
  }

  private predicate calledFromDestructor(Function f) {
    pragma[only_bind_into](f) instanceof Destructor and
    f.getDeclaringType() = this.getDeclaringType()
    or
    exists(Function mid |
      this.calledFromDestructor(mid) and
      mid.calls(f) and
      pragma[only_bind_out](f.getDeclaringType()) = pragma[only_bind_out](this.getDeclaringType())
    )
  }

  predicate inDestructor(Expr e) {
    exists(Function f | f = e.getEnclosingFunction() | this.calledFromDestructor(f))
  }

  predicate acquisitionWithRequiredKind(Assignment acquireAssign, string kind) {
    // acquireAssign is an assignment to this resource
    acquireAssign.getLValue() = this.getAnAccess() and
    // Should be in this class, but *any* member method will do
    this.inSameClass(acquireAssign) and
    // Check that it is an acquisition function and return the corresponding kind
    acquireExpr(acquireAssign.getRValue(), kind)
  }

  Expr getAReleaseExpr(string kind) { exprReleases(result, this.getAnAccess(), kind) }
}

predicate unreleasedResource(Resource r, Expr acquire, File f, int acquireLine) {
  // Note: there could be several release functions, because there could be
  // several functions called 'fclose' for example. We want to check that
  // *none* of these functions are called to release the resource
  r.acquisitionWithRequiredKind(acquire, _) and
  not exists(Expr releaseExpr, string kind |
    r.acquisitionWithRequiredKind(acquire, kind) and
    releaseExpr = r.getAReleaseExpr(kind) and
    r.inDestructor(releaseExpr)
  ) and
  f = acquire.getFile() and
  acquireLine = acquire.getLocation().getStartLine() and
  not exists(ExprCall exprCall |
    // expression call (function pointer or lambda) with `r` as an
    // argument, which could release it.
    exprCall.getAnArgument() = r.getAnAccess() and
    r.inDestructor(exprCall)
  ) and
  // check that any destructor for this class has a block; if it doesn't,
  // we must be missing information.
  forall(Class c, Destructor d |
    r.getDeclaringType().isConstructedFrom*(c) and
    d = c.getAMember() and
    not d.isCompilerGenerated() and
    not d.isDefaulted() and
    not d.isDeleted()
  |
    exists(d.getBlock())
  )
}

predicate freedInSameMethod(Resource r, Expr acquire) {
  unreleasedResource(r, acquire, _, _) and
  exists(Expr releaseExpr, string kind |
    r.acquisitionWithRequiredKind(acquire, kind) and
    releaseExpr = r.getAReleaseExpr(kind) and
    releaseExpr.getEnclosingElement+() = acquire.getEnclosingFunction()
  )
}

/**
 * Resource `r`, acquired by `acquire`, is passed to some external
 * object in the function where it's acquired.  This other object
 * may have taken responsibility for freeing the resource.
 */
predicate leakedInSameMethod(Resource r, Expr acquire) {
  unreleasedResource(r, acquire, _, _) and
  exists(Function f |
    acquire.getEnclosingFunction() = f and
    (
      exists(FunctionCall fc |
        // `r` (or something computed from it) is passed to another function
        // near to where it's acquired, and might be stored elsewhere.
        fc.getAnArgument().getAChild*() = r.getAnAccess() and
        fc.getEnclosingFunction() = f
      )
      or
      exists(Variable v, Expr e |
        // `r` (or something computed from it) is stored in another variable
        // near to where it's acquired, and might be released through that
        // variable.
        v.getAnAssignedValue() = e and
        e.getAChild*() = r.getAnAccess() and
        e.getEnclosingFunction() = f
      )
      or
      exists(FunctionCall fc |
        // `this` (i.e. the class where `r` is acquired) is passed into `r` via a
        // method, or the constructor.  `r` may use this to register itself with
        // `this` in some way, ensuring it is later deleted.
        fc.getEnclosingFunction() = f and
        fc.getAnArgument() instanceof ThisExpr and
        (
          fc.getQualifier() = r.getAnAccess() or // e.g. `r->setOwner(this)`
          fc = acquire.getAChild*() // e.g. `r = new MyClass(this)`
        )
      )
    )
  )
  or
  exists(FunctionAccess fa, string kind |
    // the address of a function that releases `r` is taken (and likely
    // used to release `r` at some point).
    r.acquisitionWithRequiredKind(acquire, kind) and
    fa.getTarget() = r.getAReleaseExpr(kind).getEnclosingFunction()
  )
}

pragma[noopt]
predicate badRelease(Resource r, Expr acquire, Function functionCallingRelease, int line) {
  unreleasedResource(r, acquire, _, _) and
  exists(Expr releaseExpr, string kind, Location releaseExprLocation, Function acquireFunction |
    r.acquisitionWithRequiredKind(acquire, kind) and
    releaseExpr = r.getAReleaseExpr(kind) and
    releaseExpr.getEnclosingFunction() = functionCallingRelease and
    functionCallingRelease.getDeclaringType() = r.getDeclaringType() and
    releaseExprLocation = releaseExpr.getLocation() and
    line = releaseExprLocation.getStartLine() and
    acquireFunction = acquire.getEnclosingFunction() and
    functionCallingRelease != acquireFunction
  )
}

Class qtObject() { result.getABaseClass*().hasGlobalName("QObject") }

PointerType qtObjectReference() { result.getBaseType() = qtObject() }

Constructor qtParentConstructor() {
  exists(Parameter p |
    p.getName() = "parent" and
    p.getType() = qtObjectReference() and
    result.getAParameter() = p and
    result.getDeclaringType() = qtObject()
  )
}

predicate automaticallyReleased(Assignment acquire) {
  // sub-types of the Qt type QObject are released by their parent (if they have one)
  exists(NewExpr alloc |
    alloc.getAllocatedType() = qtObject() and
    acquire.getRValue() = alloc and
    alloc.getInitializer() = qtParentConstructor().getACallToThisFunction()
  )
}

from Resource r, Expr acquire, File f, string message
where
  unreleasedResource(r, acquire, f, _) and
  not freedInSameMethod(r, acquire) and
  not leakedInSameMethod(r, acquire) and
  (
    exists(Function releaseFunction, int releaseLine |
      badRelease(r, acquire, releaseFunction, releaseLine) and
      message =
        "Resource " + r.getName() + " is acquired by class " + r.getDeclaringType().getName() +
          " but not released in the destructor. It is released from " + releaseFunction.getName() +
          " on line " + releaseLine +
          ", so this function may need to be called from the destructor."
    )
    or
    not badRelease(r, _, _, _) and
    message =
      "Resource " + r.getName() + " is acquired by class " + r.getDeclaringType().getName() +
        " but not released anywhere in this class."
  ) and
  not automaticallyReleased(acquire) and
  not r.getDeclaringType() instanceof TemplateClass // template classes may contain insufficient information for this analysis; results from instantiations will usually suffice.
select acquire, message

jsf/4.10 Classes/AV Rule 76.ql:
/**
 * @name AV Rule 76
 * @description A copy constructor and an assignment operator shall be declared for classes that contain pointers to data items or nontrivial destructors. If the copy constructor and assignment operators are not required, they should be explicitly disallowed.
 * @kind problem
 * @id cpp/jsf/av-rule-76
 * @problem.severity warning
 * @tags maintainability
 *       external/jsf
 */

import cpp

predicate hasPointerMember(Class c) {
  // Note: any function pointers are fine
  exists(MemberVariable v, Type t |
    v.getDeclaringType() = c and
    t = v.getType().getUnderlyingType() and
    (t instanceof PointerType or t instanceof PointerToMemberType) and
    not t instanceof FunctionPointerType and
    not t.(PointerToMemberType).getBaseType() instanceof RoutineType
  )
}

class TrivialStmt extends Stmt {
  TrivialStmt() {
    this instanceof EmptyStmt
    or
    this instanceof ReturnStmt and not this.(ReturnStmt).hasExpr()
  }
}

// What is a nontrivial destructor? JSF is unclear about that. We'll just
// take any nonempty destructor as nontrivial. Exclude the generated 'return' stmt
predicate hasNontrivialDestructor(Class c) {
  exists(Stmt s | s = c.getDestructor().getBlock().getAStmt() | not s instanceof TrivialStmt)
}

from Class c
where
  (hasPointerMember(c) or hasNontrivialDestructor(c)) and
  (
    c.hasImplicitCopyAssignmentOperator() or
    c.hasImplicitCopyConstructor()
  ) and
  not c instanceof Struct
select c,
  "AV Rule 76: A copy constructor and an assignment operator shall be declared for classes that contain pointers to data items or nontrivial destructors."

jsf/4.10 Classes/AV Rule 81.ql:
/**
 * @name AV Rule 81
 * @description The assignment operator shall handle self-assignment correctly.
 * @kind problem
 * @id cpp/jsf/av-rule-81
 * @precision low
 * @problem.severity error
 * @tags correctness
 *       external/jsf
 */

import cpp

/*
 * Note: it's almost impossible to implement this rule fully. We take a bug-finding
 * approach: try to look for some patterns that are definitely bad, while allowing
 * common patterns. Passing this query by no means implies that the implementation
 * is correct; though it probably shows that some thought has been put into it.
 * Hopefully correct implementations also pass, but 'cunning' implementations may not.
 */

/**
 * A copy assignment operator taking its parameter by reference.
 * For our purposes, copy assignment operators taking parameters by
 * value are likely fine, since the copy already happened
 */
class ReferenceCopyAssignmentOperator extends MemberFunction {
  ReferenceCopyAssignmentOperator() {
    this.getName() = "operator=" and
    this.getNumberOfParameters() = 1 and
    exists(ReferenceType rt |
      rt = this.getParameter(0).getType() and
      (
        rt.getBaseType() = this.getDeclaringType() or
        rt.getBaseType().(SpecifiedType).getBaseType() = this.getDeclaringType()
      )
    )
  }

  Parameter getRhs() { result = this.getParameter(0) }

  /** A self-equality test: between 'this' and the RHS parameter */
  IfStmt getASelfEqualityTest() {
    result.getEnclosingFunction() = this and
    exists(ComparisonOperation op |
      op = result.getCondition() and
      op.getAnOperand() instanceof ThisExpr and
      op.getAnOperand().(AddressOfExpr).getOperand().(VariableAccess).getTarget() = this.getRhs()
    )
  }

  /**
   * A call to a function called swap. Note: could be a member,
   * `std::swap` or a function overloading `std::swap` (not in `std::`)
   * so keep it simple
   */
  FunctionCall getASwapCall() {
    result.getEnclosingFunction() = this and
    result.getTarget().getName() = "swap"
  }

  /** A call to delete on a member variable */
  DeleteExpr getADeleteExpr() {
    result.getEnclosingFunction() = this and
    result.getExpr().(VariableAccess).getTarget().(MemberVariable).getDeclaringType() =
      this.getDeclaringType()
  }
}

/**
 * Test whether a class has a resource that needs management. Value class types are
 * okay because they get their semantics from their assignment operator. Primitive
 * types are fine (no management needed). Constant and reference values are okay too
 * (they can't be changed anyway). All that remains are pointer types.
 */
predicate hasResource(Class c) {
  exists(MemberVariable mv |
    mv.getDeclaringType() = c and
    mv.getType() instanceof PointerType
  )
}

from ReferenceCopyAssignmentOperator op
where
  hasResource(op.getDeclaringType()) and
  not exists(op.getASelfEqualityTest()) and
  not exists(op.getASwapCall()) and
  exists(op.getADeleteExpr())
select op, "AV Rule 81: The assignment operator shall handle self-assignment correctly."

jsf/4.10 Classes/AV Rule 82.ql:
/**
 * @name Overloaded assignment does not return 'this'
 * @description An assignment operator should return a reference to *this. Both the standard library types and the built-in types behave in this manner.
 * @kind problem
 * @problem.severity warning
 * @precision high
 * @id cpp/assignment-does-not-return-this
 * @tags reliability
 *       readability
 *       language-features
 *       external/jsf
 */

import cpp

/*
 * Applies to all assignment operators, not just the copy assignment operator.
 */

predicate callOnThis(FunctionCall fc) {
  // `this->f(...)`
  fc.getQualifier() instanceof ThisExpr
  or
  // `(*this).f(...)`
  fc.getQualifier().(PointerDereferenceExpr).getChild(0) instanceof ThisExpr
}

predicate pointerThis(Expr e) {
  e instanceof ThisExpr
  or
  // `f(...)`
  // (includes `this = ...`, where `=` is overloaded so a `FunctionCall`)
  exists(FunctionCall fc | fc = e and callOnThis(fc) | returnsPointerThis(fc.getTarget()))
  or
  // `this = ...` (where `=` is not overloaded, so an `AssignExpr`)
  pointerThis(e.(AssignExpr).getLValue())
}

predicate dereferenceThis(Expr e) {
  pointerThis(e.(PointerDereferenceExpr).getChild(0))
  or
  // `f(...)`
  // (includes `*this = ...`, where `=` is overloaded so a `FunctionCall`)
  exists(FunctionCall fc | fc = e and callOnThis(fc) | returnsDereferenceThis(fc.getTarget()))
  or
  // `*this = ...` (where `=` is not overloaded, so an `AssignExpr`)
  dereferenceThis(e.(AssignExpr).getLValue())
  or
  // `e ? ... : ... `
  exists(ConditionalExpr cond |
    cond = e and
    dereferenceThis(cond.getThen()) and
    dereferenceThis(cond.getElse())
  )
  or
  // `..., ... `
  dereferenceThis(e.(CommaExpr).getRightOperand())
}

/**
 * Holds if all `return` statements in `f` return `this`, possibly indirectly.
 * This includes functions whose body is not in the database.
 */
predicate returnsPointerThis(Function f) {
  forall(ReturnStmt s | s.getEnclosingFunction() = f and reachable(s) |
    // `return this`
    pointerThis(s.getExpr())
  )
}

/**
 * Holds if all `return` statements in `f` return a reference to `*this`,
 * possibly indirectly. This includes functions whose body is not in the
 * database.
 */
predicate returnsDereferenceThis(Function f) {
  forall(ReturnStmt s | s.getEnclosingFunction() = f and reachable(s) |
    // `return *this`
    dereferenceThis(s.getExpr())
  )
}

predicate assignOperatorWithWrongType(Operator op, string msg) {
  op.hasName("operator=") and
  exists(op.getBlock()) and
  exists(Class c |
    c = op.getDeclaringType() and
    op.getUnspecifiedType() = c and
    msg =
      "Assignment operator in class " + c.getName() + " should have return type " + c.getName() +
        "&. Otherwise a copy is created at each call."
  )
}

predicate assignOperatorWithWrongResult(Operator op, string msg) {
  op.hasName("operator=") and
  not returnsDereferenceThis(op) and
  exists(op.getBlock()) and
  not op.getType() instanceof VoidType and
  not assignOperatorWithWrongType(op, _) and
  msg =
    "Assignment operator in class " + op.getDeclaringType().getName() +
      " does not return a reference to *this."
}

from Operator op, string msg
where
  (
    assignOperatorWithWrongType(op, msg) or
    assignOperatorWithWrongResult(op, msg)
  ) and
  // exclude code in templates which may be incomplete
  not op.isFromUninstantiatedTemplate(_)
select op, msg

jsf/4.10 Classes/AV Rule 70.ql:
/**
 * @name AV Rule 70
 * @description A class will have friends only when a function or object requires access to
 *              the private elements of the class, but is unable to be a member of the class
 *              for logical or efficiency reasons.
 * @kind problem
 * @id cpp/jsf/av-rule-70
 * @problem.severity recommendation
 * @tags maintainability
 *       external/jsf
 */

import cpp

// whether b is the same as a, or b is "const a&"
predicate isTypeOrConstRef(Type a, Type b) {
  a = b
  or
  exists(ReferenceType r, SpecifiedType s |
    b = r and s = r.getBaseType() and s.hasSpecifier("const") and a = s.getUnspecifiedType()
  )
}

// whether the first parameter of f may be subject to implicit conversions
predicate implicitConvOnFirstParm(Function f) {
  exists(ImplicitConversionFunction conv |
    isTypeOrConstRef(conv.getDestType(), f.getParameter(0).getUnderlyingType())
  )
}

// whether f is declared as a friend by all its parameter types
predicate multiFriend(Function f) {
  f.getNumberOfParameters() > 1 and
  forall(Parameter p | p = f.getAParameter() |
    exists(FriendDecl fd |
      fd.getFriend() = f and
      p.getType().refersTo(fd.getDeclaringClass())
    )
  )
}

from FriendDecl fd
where
  not implicitConvOnFirstParm(fd.getFriend()) and
  not multiFriend(fd.getFriend())
select fd,
  "AV Rule 70: Friend declarations will only be used if the friend is unable to be a member of the class for logical or efficiency reasons."

jsf/4.10 Classes/AV Rule 88.ql:
/**
 * @name Undisciplined multiple inheritance
 * @description Multiple inheritance should only be used in the following restricted form: n interfaces plus m private implementations, plus at most one protected implementation. Multiple inheritance can lead to complicated inheritance hierarchies that are difficult to comprehend and maintain.
 * @kind problem
 * @problem.severity recommendation
 * @precision high
 * @id cpp/undisciplined-multiple-inheritance
 * @tags maintainability
 *       readability
 *       external/jsf
 */

import cpp

/**
 * In the context of this rule, an interface is specified by a class which has
 * the following properties:
 * - it is intended to be an interface,
 * - its public methods are pure virtual functions, and
 * - it does not hold any data, unless those data items are small and function
 *   as part of the interface (e.g. a unique object identifier).
 *
 * An approximation of this definition is classes with pure virtual functions
 * and less than 3 member variables.
 */
class InterfaceClass extends Class {
  InterfaceClass() {
    exists(MemberFunction m |
      m.getDeclaringType() = this and not compgenerated(unresolveElement(m))
    ) and
    forall(MemberFunction m |
      m.getDeclaringType() = this and not compgenerated(unresolveElement(m))
    |
      m instanceof PureVirtualFunction
    ) and
    count(MemberVariable v | v.getDeclaringType() = this) < 3
  }
}

class InterfaceImplementor extends Class {
  InterfaceImplementor() {
    exists(ClassDerivation d |
      d.getDerivedClass() = this and d.getBaseClass() instanceof InterfaceClass
    )
  }

  int getNumInterfaces() {
    result =
      count(ClassDerivation d |
        d.getDerivedClass() = this and d.getBaseClass() instanceof InterfaceClass
      )
  }

  int getNumProtectedImplementations() {
    result =
      count(ClassDerivation d |
        d.hasSpecifier("protected") and
        d.getDerivedClass() = this and
        not d.getBaseClass() instanceof InterfaceClass
      )
  }

  int getNumPrivateImplementations() {
    result =
      count(ClassDerivation d |
        d.hasSpecifier("private") and
        d.getDerivedClass() = this and
        not d.getBaseClass() instanceof InterfaceClass
      )
  }

  int getNumPublicImplementations() {
    result =
      count(ClassDerivation d |
        d.hasSpecifier("public") and
        d.getDerivedClass() = this and
        not d.getBaseClass() instanceof InterfaceClass
      )
  }
}

from InterfaceImplementor d
where
  d.getNumPublicImplementations() > 0 or
  d.getNumProtectedImplementations() > 1
select d,
  "Multiple inheritance should not be used with " + d.getNumInterfaces().toString() +
    " interfaces, " + d.getNumPrivateImplementations().toString() + " private implementations, " +
    d.getNumProtectedImplementations().toString() + " protected implementations, and " +
    d.getNumPublicImplementations().toString() + " public implementations."

jsf/4.25 Expressions/AV Rule 204.ql:
/**
 * @name AV Rule 204
 * @description A single operation with side-effects shall only be used by itself,
 *              to the right of an assignment, in a condition, as the only argument
 *              with side-effects in a function call, as a loop condition, as a switch
 *              condition, or as a part of a chained operation.
 * @kind problem
 * @id cpp/jsf/av-rule-204
 * @problem.severity warning
 * @tags maintainability
 *       readability
 *       external/jsf
 */

import cpp

// whether the main operation of e is pure (not considering its operands)
predicate isPureOperation(Expr e) {
  e instanceof Operation and
  not e instanceof Assignment and
  not e instanceof CrementOperation
}

// f is the smallest expression containing e composed entirely of
// pure operators such that e is the only non-constant subexpression
// e.g., in x = g(y) + 1, if e is g(y), then f is g(y) + 1
predicate stripOffConstants(Expr e, Expr f) {
  not isPureOperation(e.getParent()) and f = e
  or
  exists(Operation p |
    p = e.getParent() and
    isPureOperation(p) and
    (
      if forall(Expr g | g = p.getAChild() and e != g | g.isConstant())
      then stripOffConstants(p, f)
      else f = e
    )
  )
}

// whether e occurs by itself as a statement
predicate occursByItself(Expr e) {
  exists(ExprStmt s | e = s.getExpr()) or
  exists(ForStmt s | s.getUpdate() = e)
}

// whether e is the source of an assignment or an initializer
predicate isOnRightOfAssignment(Expr e) {
  exists(Assignment a | a.getRValue() = e) or
  exists(Initializer i | i.getExpr() = e)
}

// whether e is a loop condition, an if condition, or a switch expression
predicate isControllingExpr(Expr e) { exists(ControlStructure c | c.getControllingExpr() = e) }

// whether e is the only impure argument expression of a function call
predicate isSoleNonConstFunArg(Expr e) {
  exists(FunctionCall fc |
    fc.getAnArgument() = e and
    forall(Expr g | g = fc.getAnArgument() and g != e | g.isPure())
  )
}

// whether e occurs as part of a chain of qualifiers
predicate isPartOfChain(Expr e) { qualifies(e, _) or qualifies(_, e) }

// whether q qualifies e
predicate qualifies(Expr q, Expr e) {
  q = e.(Call).getQualifier() or q = e.(VariableAccess).getQualifier()
}

predicate impureExprInDisallowedContext(Expr e) {
  exists(Expr f |
    e.fromSource() and
    not e.isPure() and
    stripOffConstants(e, f) and
    not occursByItself(f) and
    not isOnRightOfAssignment(f) and
    not isControllingExpr(f) and
    not isSoleNonConstFunArg(f) and
    not isPartOfChain(f)
  )
}

from Expr e
where
  impureExprInDisallowedContext(e) and
  not e.isCompilerGenerated() and
  // A few cases that are always ok
  not e instanceof Conversion and
  not exists(@ctorinit ci | e = mkElement(ci)) and
  not exists(@dtordestruct dd | e = mkElement(dd)) and
  // Avoid flagging nested expressions
  not impureExprInDisallowedContext(e.getParent+())
select e.findRootCause(),
  "AV Rule 204: A single operation with side-effects shall only be used in certain contexts."

jsf/4.14 Comments/AV Rule 133.ql:
/**
 * @name AV Rule 133
 * @description Every source file will be documented with an introductory comment that provides information on the file name, its contents, and any program-required information (eg. legal statements, copyright information, etc)
 * @kind problem
 * @id cpp/jsf/av-rule-133
 * @problem.severity recommendation
 * @tags maintainability
 *       documentation
 *       external/jsf
 */

import cpp

class FirstComment extends Comment {
  FirstComment() {
    not exists(Locatable l |
      l != this and
      shouldNotBeBefore(l) and
      l.getFile() = this.getFile() and
      l.getLocation().getEndLine() <= this.getLocation().getStartLine()
    )
  }

  /*
   * Test whether the comment is a reasonable start-of-file comment.
   * CUSTOMIZATION POINT: INSERT STYLE RULES FOR THE START-OF-FILE COMMENT HERE
   * Simple checks only - if there is a comment at the beginning of the file, that
   * is pretty much enough
   */

  predicate isValid() {
    // At least 3 lines long: make sure it's a proper comment
    this.getLocation().getEndLine() >= this.getLocation().getStartLine() + 2 and
    exists(string contents | contents = this.getContents() |
      // Make sure the name of the file is included
      contents.matches("%" + this.getFile().getShortName() + "%")
      // Other checks could go here; for instance containing a standard copyright notice
    )
  }
}

/** Elements that should not appear before the 'first' comment */
predicate shouldNotBeBefore(Locatable l) {
  l instanceof Comment or
  l instanceof Declaration or
  l instanceof PreprocessorDirective
}

from File f, Element blame, string message
where
  f.fromSource() and
  (
    not exists(FirstComment comment | comment.getFile() = f) and
    blame = f and
    message = ""
    or
    exists(FirstComment comment |
      comment.getFile() = f and not comment.isValid() and blame = comment
    ) and
    message = "The introductory comment does not match the required style rules."
  )
select blame,
  "AV Rule 133: every source file will be documented with an introductory comment. " + message

jsf/4.17 Types/AV Rule 147.ql:
/**
 * @name Do not expose float representation
 * @description The underlying bit representation of floating point numbers should not be used in any way by the programmer. This leads to non-portable and hard to maintain code.
 * @kind problem
 * @id cpp/jsf/av-rule-147
 * @problem.severity error
 * @tags reliability
 *       external/jsf
 */

import cpp

/*
 * The bit representation of a float can be exposed by:
 *  - casting a float pointer to another pointer type
 *  - casting a float array to a non-float pointer type
 *  - using a float in a union with at least one non-float member
 */

class GeneralPointerType extends DerivedType {
  GeneralPointerType() { this instanceof PointerType or this instanceof ArrayType }
}

class InvalidFloatCastExpr extends Expr {
  InvalidFloatCastExpr() {
    exists(Type src, Type dst |
      src = this.getUnspecifiedType() and
      dst = this.getFullyConverted().getUnspecifiedType() and
      src.(GeneralPointerType).getBaseType() instanceof FloatingPointType and
      src.(GeneralPointerType).getBaseType() != dst.(GeneralPointerType).getBaseType()
    )
  }
}

class FloatUnion extends Union {
  FloatUnion() {
    exists(MemberVariable mv |
      this.getAMemberVariable() = mv and
      mv.getType().getUnderlyingType() instanceof FloatingPointType
    ) and
    exists(MemberVariable mv |
      this.getAMemberVariable() = mv and
      not mv.getType().getUnderlyingType() instanceof FloatingPointType
    )
  }

  MemberVariable getAFloatMember() {
    result = this.getAMemberVariable() and
    result.getType().getUnderlyingType() instanceof FloatingPointType
  }
}

from Element e, string message
where
  e instanceof InvalidFloatCastExpr and
  message =
    "Casting a float pointer to another pointer type exposes the bit representation of the float, leading to unportable code."
  or
  exists(FloatUnion fu | e = fu.getAFloatMember()) and
  message =
    "Defining a union with a float member exposes the bit representation of the float, leading to unportable code."
select e, message

jsf/4.28 Portable Code/AV Rule 212.ql:
/**
 * @name AV Rule 212
 * @description Underflow or overflow functioning shall not be depended on
 *              in any special way.
 * @kind problem
 * @id cpp/jsf/av-rule-212
 * @problem.severity error
 * @tags correctness
 *       portability
 *       external/jsf
 */

import cpp

/*
 * This query checks for the use of the "a + b < a" idiom.
 */

predicate isNonNegative(Expr e) {
  e.getUnderlyingType().(IntegralType).isUnsigned() or
  e.getValue().toInt() >= 0
}

predicate sameExpr(Expr e, Expr f) {
  e.(VariableAccess).getTarget() = f.(VariableAccess).getTarget()
  // adding the following disjunct OOMs on non-trivial databases
  //or e.getValue() = f.getValue()
}

class UnreliableOverflowTest extends LTExpr {
  UnreliableOverflowTest() {
    exists(AddExpr l, Expr a, Expr b, Expr r |
      l = super.getLeftOperand() and
      a = l.getLeftOperand() and
      b = l.getRightOperand() and
      r = super.getRightOperand() and
      (
        sameExpr(a, r) and isNonNegative(b)
        or
        sameExpr(b, r) and isNonNegative(a)
      )
    )
  }
}

from UnreliableOverflowTest t
select t, "AV Rule 212: Underflow or overflow functioning shall not be depended on."

jsf/4.28 Portable Code/AV Rule 214.ql:
/**
 * @name AV Rule 214
 * @description Assuming that non-local static objects, in separate translation units,
 *              are initialized in a special order shall not be done.
 * @kind problem
 * @id cpp/jsf/av-rule-214
 * @problem.severity error
 * @tags correctness
 *       external/jsf
 */

import cpp

// whether e is part of an initializer of a global variable in file f
predicate inGlobalInitializer(Expr e, File f) {
  exists(GlobalVariable gv |
    gv.getInitializer().getExpr() = e.getParent*() and
    f = gv.getFile()
  )
}

// whether c is called from within a global initializer in f
// TODO: this should be transitive, but maybe it's not worth the extra hassle
predicate calledFromGlobalInitializer(Function fn, File f) {
  exists(FunctionCall c | inGlobalInitializer(c, f) and fn = c.getTarget())
}

predicate evaluatedBeforeMain(Expr e, File f) {
  inGlobalInitializer(e, f)
  or
  exists(Function fn | calledFromGlobalInitializer(fn, f) and fn = e.getControlFlowScope())
}

// whether f1 and f2 belong to the same translation unit
predicate sameTranslationUnit(File f1, File f2) {
  exists(File f | f.getAnIncludedFile*() = f1 and f.getAnIncludedFile*() = f2)
}

from VariableAccess v, File f1, File f2
where
  v.fromSource() and
  v.isRValue() and
  evaluatedBeforeMain(v, f1) and
  v.getTarget().getFile() = f2 and
  not sameTranslationUnit(f1, f2)
select v,
  "AV Rule 214: It shall not be assumed that objects in separated translation units are initialized in a special order."

jsf/4.21 Operators/AV Rule 160.ql:
/**
 * @name AV Rule 160
 * @description An assignment expression shall be used only as the expression in an expression statement.
 * @kind problem
 * @id cpp/jsf/av-rule-160
 * @problem.severity warning
 * @tags correctness
 *       readability
 *       external/jsf
 */

import cpp

predicate multipleAssignExpr(Expr e) {
  e instanceof AssignExpr
  or
  exists(CommaExpr ce | ce = e |
    multipleAssignExpr(ce.getLeftOperand()) and
    multipleAssignExpr(ce.getRightOperand())
  )
}

class MultipleAssignExpr extends Expr {
  MultipleAssignExpr() { multipleAssignExpr(this) }

  Assignment getAnAssignment() { result = this.getAChild*() }
}

class ForStmtSideEffectExpr extends Expr {
  ForStmtSideEffectExpr() {
    exists(ForStmt stmt |
      this = stmt.getUpdate() or
      this = stmt.getInitialization().getAChild().(MultipleAssignExpr).getAnAssignment()
    )
  }
}

from AssignExpr ae
where
  ae.fromSource() and
  not ae.getParent() instanceof ExprStmt and
  not ae instanceof ForStmtSideEffectExpr
select ae,
  "AV Rule 160: An assignment expression shall be used only as the expression in an expression statement."

jsf/4.09 Style/AV Rule 58.ql:
/**
 * @name AV Rule 58
 * @description When declaring and defining functions with more than two parameters, the leading parenthesis and the first argument will be written on the same line as the function name. Each additional argument will be written on a separate line (with the closing parenthesis directly after the last argument).
 * @kind problem
 * @id cpp/jsf/av-rule-58
 * @problem.severity recommendation
 * @tags maintainability
 *       readability
 *       external/jsf
 */

import cpp

class ParamLoc extends Parameter {
  int getValidLine() {
    result = this.getLocation().getStartLine() and result = this.getLocation().getEndLine()
  }
}

predicate valid(Function f) {
  // Check that the first parameter is okay
  f.getParameter(0).(ParamLoc).getValidLine() = f.getLocation().getStartLine() and
  // Check that each subsequent parameter is on its own line
  not exists(ParamLoc p1, ParamLoc p2 |
    p1 = f.getAParameter() and
    p2 = f.getAParameter() and
    p1 != p2 and
    p1.getValidLine() = p2.getValidLine()
  ) and
  // Check that there are no parameters on two lines
  forall(ParamLoc p | p = f.getAParameter() | exists(p.getValidLine()))
}

from Function f
where
  f.getNumberOfParameters() > 2 and
  f.hasDefinition() and
  not valid(f)
select f,
  "AV Rule 58: functions with more than two parameters will conform to style rules for declaring parameters."

jsf/4.15 Declarations and Definitions/AV:
/**
 * @name Hiding identifiers
 * @description Identifiers in an inner scope should not use the same name as an identifier in an outer scope, and therefore hide that identifier.
 * @kind problem
 * @id cpp/jsf/av-rule-135
 * @problem.severity recommendation
 * @tags maintainability
 *       external/jsf
 */

import cpp
import Best_Practices.Hiding.Shadowing

// Shadowing globals by locals or parameters. Only in the same file;
// otherwise the rule is violated too often
class LocalVariableOrParameter extends Variable {
  LocalVariableOrParameter() { this instanceof LocalVariable or this instanceof Parameter }

  predicate shadowsGlobal(GlobalVariable gv) {
    this.getName() = gv.getName() and this.getFile() = gv.getFile()
  }
}

// Shadowing parameters by locals
predicate localShadowsParameter(LocalVariable lv, Parameter p) {
  p.getName() = lv.getName() and
  p.getFunction() = lv.getFunction()
}

from Variable v, Variable shadowed
where
  not v.getParentScope().(BlockStmt).isInMacroExpansion() and
  (
    v.(LocalVariableOrParameter).shadowsGlobal(shadowed) or
    localShadowsParameter(v, shadowed) or
    shadowing(v, shadowed)
  )
select v, "Identifiers in an inner scope should not hide identifiers in an outer scope."

jsf/4.13 Functions/AV Rule 115.ql:
/**
 * @name AV Rule 115
 * @description If a function returns error information, then that
 *              information will be tested.
 * @kind problem
 * @id cpp/jsf/av-rule-115
 * @problem.severity warning
 * @tags correctness
 *       external/jsf
 */

import cpp

// a return statement that looks like it returns an error code
// we use an extremely simple approximation: any return statement that returns
// a literal or a symbolic constant is considered to return an error code; we
// make an exception for integral constant zero, which often indicates success
// (unlike, of course, the null pointer)
class ErrorReturn extends ReturnStmt {
  ErrorReturn() {
    exists(Expr e |
      e = super.getExpr() and
      (
        e instanceof Literal or
        e.(VariableAccess).getTarget().isConst()
      ) and
      not (e.getValue() = "0" and e.getActualType() instanceof IntegralType)
    )
  }
}

// a function that has both a return statement returning an error code, and one that doesn't
class FunctionReturningErrorCode extends Function {
  FunctionReturningErrorCode() {
    exists(ErrorReturn er, ReturnStmt nr |
      er.getEnclosingFunction() = this and
      nr.getEnclosingFunction() = this and
      not nr instanceof ErrorReturn
    )
  }
}

from FunctionReturningErrorCode frec, Call c
where
  c = frec.getACallToThisFunction() and
  c instanceof ExprInVoidContext
select c, "AV Rule 115: If a function returns error information, it will be tested."

jsf/4.16 Initialization/AV Rule 145.ql:
/**
 * @name Irregular enum initialization
 * @description In an enumerator list, the = construct should not be used to explicitly initialize members other than the first, unless all items are explicitly initialized. An exception is the pattern to use the last element of an enumerator list to get the number of possible values.
 * @kind problem
 * @problem.severity recommendation
 * @precision high
 * @id cpp/irregular-enum-init
 * @tags reliability
 *       readability
 *       language-features
 *       external/jsf
 */

import cpp

predicate hasInitializer(EnumConstant c) { c.getInitializer().fromSource() }

/** Does this have an initializer that is not just a ref to another constant in the same enum? */
predicate hasNonReferenceInitializer(EnumConstant c) {
  exists(Initializer init |
    init = c.getInitializer() and
    init.fromSource() and
    not init.getExpr().(EnumConstantAccess).getTarget().getDeclaringEnum() = c.getDeclaringEnum()
  )
}

predicate hasReferenceInitializer(EnumConstant c) {
  exists(Initializer init |
    init = c.getInitializer() and
    init.fromSource() and
    init.getExpr().(EnumConstantAccess).getTarget().getDeclaringEnum() = c.getDeclaringEnum()
  )
}

/**
 * Gets the `rnk`'th (1-based) enumeration constant in `e` that does not have a
 * reference initializer (i.e., an initializer that refers to an enumeration
 * constant from the same enumeration).
 */
EnumConstant getNonReferenceInitializedEnumConstantByRank(Enum e, int rnk) {
  result =
    rank[rnk](EnumConstant cand, int pos, string filepath, int startline, int startcolumn |
      e.getEnumConstant(pos) = cand and
      not hasReferenceInitializer(cand) and
      cand.getLocation().hasLocationInfo(filepath, startline, startcolumn, _, _)
    |
      cand order by pos, filepath, startline, startcolumn
    )
}

/**
 * Holds if `ec` is not the last enumeration constant in `e` that has a non-
 * reference initializer.
 */
predicate hasNextWithoutReferenceInitializer(Enum e, EnumConstant ec) {
  exists(int rnk |
    ec = getNonReferenceInitializedEnumConstantByRank(e, rnk) and
    exists(getNonReferenceInitializedEnumConstantByRank(e, rnk + 1))
  )
}

// There exists another constant whose value is implicit, but it's
// not the last one: the last value is okay to use to get the highest
// enum value automatically. It can be followed by aliases though.
predicate enumThatHasConstantWithImplicitValue(Enum e) {
  exists(EnumConstant ec |
    ec = e.getAnEnumConstant() and
    not hasInitializer(ec) and
    hasNextWithoutReferenceInitializer(e, ec)
  )
}

from Enum e, int i
where
  // e is at position i, and has an explicit value in the source - but
  // not just a reference to another enum constant
  hasNonReferenceInitializer(e.getEnumConstant(i)) and
  // but e is not the first or the last constant of the enum
  i != 0 and
  exists(e.getEnumConstant(i + 1)) and
  // and there exists another constant whose value is implicit, but it's
  // not the last one: the last value is okay to use to get the highest
  // enum value automatically. It can be followed by aliases though.
  enumThatHasConstantWithImplicitValue(e)
select e,
  "In an enumerator list, the = construct should not be used to explicitly initialize members other than the first, unless all items are explicitly initialized."

jsf/4.16 Initialization/AV Rule 142.ql:
/**
 * @name AV Rule 142
 * @description All variables shall be initialized before use.
 * @kind problem
 * @id cpp/jsf/av-rule-142
 * @problem.severity error
 * @tags correctness
 *       external/jsf
 */

import cpp

// whether s defines variable v (conservative)
predicate defines(ControlFlowNode s, Variable lv) {
  exists(VariableAccess va | va = s and va.getTarget() = lv and va.isLValue())
}

// whether s uses variable v (conservative)
predicate uses(ControlFlowNode s, Variable lv) {
  exists(VariableAccess va |
    va = s and
    va.getTarget() = lv and
    va.isRValue() and
    not va.getParent+() instanceof SizeofOperator
  )
}

// whether there is a path from the declaration of lv to n such that lv is definitely not defined before n
predicate noDefPath(LocalVariable lv, ControlFlowNode n) {
  n.(DeclStmt).getADeclaration() = lv and not exists(lv.getInitializer())
  or
  exists(ControlFlowNode p | noDefPath(lv, p) and n = p.getASuccessor() and not defines(p, lv))
}

predicate isAggregateType(Type t) { t instanceof Class or t instanceof ArrayType }

// whether va is a use of a local variable that has not been previously defined
predicate undefinedLocalUse(VariableAccess va) {
  exists(LocalVariable lv |
    // it is hard to tell when a struct or array has been initialised, so we ignore them
    not isAggregateType(lv.getUnderlyingType()) and
    not lv.getType().hasName("va_list") and
    va = lv.getAnAccess() and
    noDefPath(lv, va) and
    uses(va, lv)
  )
}

// whether gv is a potentially uninitialised global variable
predicate uninitialisedGlobal(GlobalVariable gv) {
  exists(VariableAccess va |
    not isAggregateType(gv.getUnderlyingType()) and
    va = gv.getAnAccess() and
    va.isRValue() and
    not gv.hasInitializer() and
    not gv.hasSpecifier("extern")
  )
}

from Element elt
where undefinedLocalUse(elt) or uninitialisedGlobal(elt)
select elt, "AV Rule 142: All variables shall be initialized before use."

jsf/4.07 Header Files/AV Rule 35.ql:
/**
 * @name Missing header guard
 * @description Header files should contain header guards (#defines to prevent
 *              the file from being included twice). This prevents errors and
 *              inefficiencies caused by repeated inclusion.
 * @kind problem
 * @problem.severity recommendation
 * @precision high
 * @id cpp/missing-header-guard
 * @tags efficiency
 *       maintainability
 *       modularity
 *       external/jsf
 */

import cpp
import semmle.code.cpp.headers.MultipleInclusion

string possibleGuard(HeaderFile hf, string body) {
  exists(Macro m | m.getFile() = hf and m.getBody() = body | result = m.getHead())
}

/**
 * Option type for preprocessor directives so we can produce a variable number
 * of links in the result
 */
newtype TMaybePreprocessorDirective =
  TSomePreprocessorDirective(PreprocessorDirective pd) or
  TNoPreprocessorDirective()

abstract class MaybePreprocessorDirective extends TMaybePreprocessorDirective {
  abstract string toString();

  abstract Location getLocation();
}

class NoPreprocessorDirective extends TNoPreprocessorDirective, MaybePreprocessorDirective {
  override string toString() { result = "" }

  override Location getLocation() { result instanceof UnknownLocation }
}

class SomePreprocessorDirective extends TSomePreprocessorDirective, MaybePreprocessorDirective {
  PreprocessorDirective pd;

  SomePreprocessorDirective() { this = TSomePreprocessorDirective(pd) }

  override string toString() { result = pd.toString() }

  override Location getLocation() { result = pd.getLocation() }

  PreprocessorDirective getPreprocessorDirective() { result = pd }
}

/**
 * Provides additional detail when there is an incorrect header guard.
 * The second and third parameters are option typed, and are only present
 * when there are additional links in the detail string.
 */
string extraDetail(
  HeaderFile hf, SomePreprocessorDirective detail1, SomePreprocessorDirective detail2
) {
  exists(string s, PreprocessorEndif endif, PreprocessorDirective ifndef |
    startsWithIfndef(hf, ifndef, s) and endif.getIf() = ifndef
  |
    detail1.getPreprocessorDirective() = endif and
    detail2.getPreprocessorDirective() = ifndef and
    if not endsWithEndif(hf, endif)
    then result = " ($@ matching $@ occurs before the end of the file)."
    else
      if exists(Macro m | m.getFile() = hf and m.getHead() = s)
      then result = " (#define " + s + " needs to appear immediately after #ifndef " + s + ")."
      else
        if strictcount(possibleGuard(hf, _)) = 1
        then
          result =
            " (" + possibleGuard(hf, _) + " should appear in the #ifndef rather than " + s + ")."
        else
          if strictcount(possibleGuard(hf, "")) = 1
          then
            result =
              " (" + possibleGuard(hf, "") + " should appear in the #ifndef rather than " + s + ")."
          else result = " (the macro " + s + " is checked for, but is not defined)."
  )
}

/**
 * Header file `hf` uses a macro called `macroName`.
 */
predicate usesMacro(HeaderFile hf, string macroName) {
  not hf instanceof IncludeGuardedHeader and // restrict to cases the query looks at
  exists(MacroAccess ma |
    ma.getFile() = hf and
    ma.getMacro().getName() = macroName
  )
}

/** File `f` defines a macro called `macroName`. */
predicate definesMacro(File f, string macroName) {
  exists(Macro m |
    m.getFile() = f and
    m.getName() = macroName
  )
}

/** File `f` un-defines a macro called `macroName`. */
predicate undefinesMacro(File f, string macroName) {
  exists(PreprocessorUndef ud |
    ud.getFile() = f and
    ud.getName() = macroName
  )
}

/**
 * File `f` both defines and un-defines a macro called `macroName`.
 */
predicate defUndef(File f, string macroName) {
  definesMacro(f, macroName) and
  undefinesMacro(f, macroName)
}

/**
 * Header file `hf` looks like it contains an x-macro.
 * That is, a macro that is used to interpret the
 * data in `hf`, usually defined just before including that file
 * and undefined immediately afterwards.
 */
predicate hasXMacro(HeaderFile hf) {
  // Every header that includes `hf` both defines and undefines a macro that's
  // used in `hf`.
  exists(string macroName |
    usesMacro(hf, macroName) and
    forex(File f | f.getAnIncludedFile() = hf | defUndef(f, macroName))
  )
  or
  // Every header that includes `hf` defines a macro that's used in `hf`, and
  // `hf` itself undefines it.
  exists(string macroName |
    usesMacro(hf, macroName) and
    undefinesMacro(hf, macroName) and
    forex(File f | f.getAnIncludedFile() = hf | definesMacro(f, macroName))
  )
}

from
  HeaderFile hf, string detail, MaybePreprocessorDirective detail1,
  MaybePreprocessorDirective detail2
where
  not hf instanceof IncludeGuardedHeader and
  (
    if exists(extraDetail(hf, _, _))
    then detail = extraDetail(hf, detail1, detail2)
    else (
      detail = "." and
      detail1 instanceof NoPreprocessorDirective and
      detail2 instanceof NoPreprocessorDirective
    )
  ) and
  // Exclude files which contain no declaration entries or top level
  // declarations (e.g. just preprocessor directives; or non-top level
  // code).
  not hf.noTopLevelCode() and
  // Exclude files which look like they contain 'x-macros'
  not hasXMacro(hf) and
  // Exclude files which are always #imported.
  not forex(Include i | i.getIncludedFile() = hf | i instanceof Import) and
  // Exclude files which are only included once.
  not strictcount(Include i | i.getIncludedFile() = hf) = 1
select hf, "This header file should contain a header guard to prevent multiple inclusion" + detail,
  detail1, detail1.toString(), detail2, detail2.toString()

jsf/4.06 Pre-Processing Directives/AV Ru:
/**
 * @name AV Rule 30
 * @description The #define pre-processor directive shall not be used to define constant values. Instead, the const qualifier shall be applied to variable declarations to specify constant values.
 * @kind problem
 * @id cpp/jsf/av-rule-30
 * @problem.severity error
 * @tags maintainability
 *       external/jsf
 */

import cpp

/** A macro defining a simple constant. */
class ConstantDefMacro extends Macro {
  ConstantDefMacro() {
    // Exclude functions
    not this.getHead().matches("%(%") and
    exists(string body |
      body = this.getBody() and
      // Empty defines are allowed (rule 31 restricts their use though)
      body != "" and
      // No special characters in the body
      not body.matches("%(%") and
      not body.matches("%{%")
    )
  }
}

/** List macros that are 'common' and should be excluded */
predicate commonMacro(string name) {
  name = "NULL" // TODO
}

from ConstantDefMacro m
where
  not commonMacro(m.getHead()) and
  m.fromSource()
select m, "The #define pre-processor directive shall not be used to define constant values."

jsf/4.05 Libraries/AV Rule 20.ql:
/**
 * @name AV Rule 20
 * @description The setjmp macro and the longjmp function shall not be used.
 * @kind problem
 * @id cpp/jsf/av-rule-20
 * @problem.severity warning
 * @tags correctness
 *       portability
 *       readability
 *       external/jsf
 */

import cpp

class Setjmp extends Macro {
  Setjmp() {
    super.getHead().matches("setjmp(%)") and
    super.getFile().getAbsolutePath().matches("%setjmp.h")
  }
}

class Longjmp extends Function {
  Longjmp() {
    super.hasName("longjmp") and
    super.getNumberOfParameters() = 2 and
    super.getFile().getAbsolutePath().matches("%setjmp.h")
  }
}

from Setjmp setjmp, Longjmp longjmp, Locatable use
where
  use = setjmp.getAnInvocation() or
  use = longjmp.getACallToThisFunction()
select use, "AV Rule 20: The setjmp macro and the longjmp function shall not be used."

jsf/4.23 Type Conversions/AV Rule 180.ql:
/**
 * @name AV Rule 180
 * @description Implicit conversions that may result in a loss of information
 *              shall not be used.
 * @kind problem
 * @id cpp/jsf/av-rule-180
 * @problem.severity warning
 * @tags correctness
 *       external/jsf
 */

import cpp

class IntConstantExpr extends Expr {
  IntConstantExpr() {
    this.getType() instanceof IntegralType and
    exists(this.getValue())
  }

  int getIntValue() { result = this.getValue().toInt() }

  predicate isNegative() { this.getIntValue() < 0 }

  /**
   * Find out how many (8, 16, 32, 64) bits are required.
   *      FIXME Currently only works up to 32 bits
   */
  int getRequiredSizeBits() {
    exists(int value |
      value = this.getIntValue() and
      (
        value < -32768 and result = 32
        or
        value >= -32768 and value < -128 and result = 16
        or
        value >= -128 and value < 0 and result = 8
        or
        value >= 0 and value < 128 and result = 7
        or
        value >= 128 and value < 256 and result = 8
        or
        value >= 256 and value < 32768 and result = 15
        or
        value >= 32768 and value < 65536 and result = 16
        or
        value >= 65536 and value <= 2147483647 and result = 31
        or
        value > 2147483647 and result = 32
      )
    )
  }
}

class ImplicitConversion extends Expr {
  ImplicitConversion() { super.hasImplicitConversion() }

  Type getUnderlyingSourceType() { result = this.getUnderlyingType() }

  Type getUnderlyingTargetType() { result = this.getConversion().getUnderlyingType() }

  int getSourceSize() {
    if this instanceof IntConstantExpr
    then result = this.(IntConstantExpr).getRequiredSizeBits()
    else result = this.getUnderlyingSourceType().getSize() * 8
  }

  int getTargetSize() { result = this.getUnderlyingTargetType().getSize() * 8 }

  predicate isSourceSignedInt() {
    if this instanceof IntConstantExpr
    then this.(IntConstantExpr).isNegative()
    else this.getUnderlyingSourceType().(IntegralType).isSigned()
  }

  predicate isTargetSignedInt() { this.getUnderlyingTargetType().(IntegralType).isSigned() }
}

class LossyImplicitConversion extends ImplicitConversion {
  LossyImplicitConversion() {
    // conversion to smaller type
    super.getTargetSize() < super.getSourceSize()
    or
    // signed to unsigned conversion
    super.isSourceSignedInt() and not super.isTargetSignedInt()
    or
    // unsigned to signed conversion without increasing size
    not super.isSourceSignedInt() and
    super.isTargetSignedInt() and
    super.getTargetSize() = super.getSourceSize()
    or
    // floating-integral conversion
    super.getUnderlyingSourceType() instanceof FloatingPointType and
    super.getUnderlyingTargetType() instanceof IntegralType
    or
    // integral-floating conversion
    super.getUnderlyingSourceType() instanceof IntegralType and
    super.getUnderlyingTargetType() instanceof FloatingPointType
  }
}

from LossyImplicitConversion lic
where
  // Conversions to bool are always fine
  not lic.getUnderlyingTargetType() instanceof BoolType
select lic,
  "AV Rule 180: implicit conversion from " + lic.getUnderlyingSourceType().toString() + " to " +
    lic.getUnderlyingTargetType().toString() + " may lose information."
